input group "=== LOGGING ==="
input bool   EnableCSV          = true;
input string CSVFileName        = "BreakoutNY_v9_trades";

input group "=== VISUAL ==="
input bool   VIS_Enable         = true;  // Activar indicador visual
input int    VIS_LookbackDays   = 25;    // Días históricos a dibujar
input int    VIS_ExtendBars     = 50;    // Velas que se extienden los niveles
input bool   VIS_ShowBE         = true;  // Mostrar línea de BreakEven
input bool   VIS_ShowLabel      = true;  // Mostrar etiqueta resumen
