input color  VIS_ColRangeBorder = C'55,115,215';  // Borde HIGH/LOW del rango
input color  VIS_ColSL          = C'220,50,70';   // SL
input color  VIS_ColEntry       = C'195,208,230'; // Entry
input color  VIS_ColBE          = C'0,195,218';   // BreakEven
input color  VIS_ColTP1         = C'228,188,38';  // TP1
input color  VIS_ColTP2         = C'228,128,28';  // TP2
input color  VIS_ColTP3         = C'28,208,128';  // TP3

input group "=== CONFIGURACIÓN ==="
input ulong  MagicNumber        = 202401;

//===================================================================
//  VARIABLES GLOBALES — TRADING
//===================================================================

CTrade        trade;
CPositionInfo posInfo;

// Estado diario
bool     rangeCalculated = false;
bool     tradeExecuted   = false;
bool     dayFiltered     = false;
bool     rangeFiltered   = false;
double   rangeHigh       = 0;
double   rangeLow        = 0;
double   slDistance      = 0;
datetime lastTradeDay    = 0;

// Estado operación activa
ulong    activeTicket    = 0;
double   entryPrice      = 0;
