   Print("Visual         : ", VIS_Enable ? "ACTIVO — Entry/SL/TP coinciden con la operación real" : "DESACTIVADO");

   // Dibujar histórico al arrancar
   VisRedrawAll();

   return INIT_SUCCEEDED;
}

