//===================================================================
//  PARÁMETROS DE ENTRADA
//===================================================================

input group "=== HORARIO ==="
input int    ServerOffsetHours  = 2;     // Offset servidor vs UTC — FundingPips UTC+2 (verificar DST)
input int    EntryWindowEnd_Min = 15;    // Minuto fin ventana (14:50 – 15:HH UTC)
input int    SessionCloseHour   = 17;    // Hora cierre forzoso UTC — NO CAMBIAR
input int    SessionCloseMin    = 0;     // Minuto cierre forzoso UTC

input group "=== RIESGO ==="
