input group "=== OBJETIVOS ==="
input double TP1_RR             = 1.0;   // TP1 — activa BE
input double TP2_RR             = 2.0;   // TP2 — SL sube a TP1
input double TP3_RR             = 3.0;   // TP3 — target final

input group "=== CIERRES PARCIALES ==="
input bool   EnablePartials     = false; // false = todo a TP3 (backtest base)
input int    TP1_ClosePct       = 40;    // % del lote a cerrar en TP1 (0-60)
input int    TP2_ClosePct       = 40;    // % del lote a cerrar en TP2 (0-60)

input group "=== BREAKEVEN ==="
input double BE_BufferPct       = 50.0;  // % del SL original como precio de BE
                                          // 50% = BE activa cuando precio recorre 50% del SL

input group "=== FILTROS DÍA SEMANA ==="
input bool   FilterMonday       = true;  // true=OPERA | false=FILTRA
                                          // ⚠ INICIAR con todos true — medir antes de filtrar
input bool   FilterTuesday      = true;
input bool   FilterWednesday    = true;  // Medir primero — en DJI30 fue el peor día
input bool   FilterThursday     = true;
input bool   FilterFriday       = true;  // XAUUSD cierre de semana puede ser volátil — medir

input group "=== FILTROS RANGO ==="
input double MinSL_Points       = 100.0; // PROVISIONAL — correr Calibrador primero (P50 histórico)
                                          // En DJI30 era ~P25; para XAUUSD usar P50 por mayor volatilidad
                                          // Rango típico XAUUSD pre-NY: 80-400 puntos ($0.80-$4 con _Point=0.01)
input double MaxSL_Points       = 500.0; // PROVISIONAL — correr Calibrador primero (~P90 histórico)
input bool   ConfirmOnClose     = true;  // SIEMPRE true — no optimizar

input group "=== FILTRO ATR (VOLATILIDAD) ==="
input bool   ATR_FilterEnable   = true;  // SIEMPRE true — crítico para XAUUSD
input int    ATR_Period         = 14;    // Período ATR (velas M5)
input double ATR_MaxMultiplier  = 1.5;   // XAUUSD: 1.5 vs 2.0 del DJI30 — más estricto por volatilidad
input double ATR_MinMultiplier  = 0.3;   // Punto de inicio — optimizar en IS
input int    ATR_BaselineDays   = 20;    // Días lookback baseline ATR

input group "=== FILTRO DE TENDENCIA INTRADIARIA (Experimental) ==="
