double OnTester()
{
   if(stat_total == 0) return 0;
   double wr   = (stat_total > 0) ? (double)stat_wins / stat_total * 100.0 : 0;
   double pf   = (stat_grossLoss != 0) ? stat_grossProfit / MathAbs(stat_grossLoss) : 0;
   Print("=== RESUMEN XAUUSD BreakoutNY v1.0 ===");
   Print("Trades : ", stat_total, " (W=", stat_wins, " / L=", stat_losses, ")");
   Print("WinRate: ", DoubleToString(wr, 2), "%");
   Print("PF     : ", DoubleToString(pf, 3));
   Print("Gross+ : $", DoubleToString(stat_grossProfit, 2));
   Print("Gross- : $", DoubleToString(stat_grossLoss, 2));
   Print("Net    : $", DoubleToString(stat_grossProfit + stat_grossLoss, 2));
   return pf;
}

//===================================================================
//  OnInit — diagnóstico completo del símbolo
//===================================================================

int OnInit()
{
   // Validaciones de parámetros (idénticas al DJI30 v4)
   if(TP1_RR <= 0 || TP2_RR <= TP1_RR || TP3_RR <= TP2_RR)
   {
      Alert("ERROR: TP1_RR < TP2_RR < TP3_RR deben ser crecientes y positivos.");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(TP1_ClosePct < 0 || TP1_ClosePct > 60 || TP2_ClosePct < 0 || TP2_ClosePct > 60)
   {
      Alert("ERROR: TP1_ClosePct y TP2_ClosePct deben estar entre 0 y 60.");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(TP1_ClosePct + TP2_ClosePct >= 100)
   {
      Alert("ERROR: TP1_ClosePct + TP2_ClosePct debe ser < 100.");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(BE_BufferPct < 0 || BE_BufferPct > 99)
   {
      Alert("ERROR: BE_BufferPct debe estar entre 0 y 99.");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(MagicNumber != 202404)
   {
      Print("ADVERTENCIA: MagicNumber=", MagicNumber,
            " — el estándar para XAUUSD es 202404. Verificar conflicto.");
   }

   trade.SetExpertMagicNumber(MagicNumber);
   InitCSV();

   //--- DIAGNÓSTICO COMPLETO DEL SÍMBOLO XAUUSD ---
   double _tv  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double _ts  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double _cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double _pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double _mn  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double _mx  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   int    _dg  = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);

   string _method = (_tv > 0 && _ts > 0) ? "MÉTODO 1 (tv/ts)" : "MÉTODO 2 FALLBACK (CS×Pt)";
   double _vpp = (_tv > 0 && _ts > 0) ? _tv / _ts : _cs * _pt;

   Print("==========================================================");
   Print("=== BreakoutNY XAUUSD v1.0 — DIAGNÓSTICO DE SÍMBOLO ===");
   Print("==========================================================");
   Print("Símbolo        : ", _Symbol);
   Print("Dígitos        : ", _dg);
   Print("ContractSize   : ", _cs, " oz");
   Print("TickSize       : ", _ts);
   Print("TickValue      : ", _tv);
   Print("Point (_Point) : ", _pt);
   Print("Spread actual  : ", SymbolInfoInteger(_Symbol, SYMBOL_SPREAD), " puntos broker");
   Print("VolumeMin      : ", _mn);
   Print("VolumeMax      : ", _mx, " (forzado a 5 en XAUUSD FundingPips)");
   Print("Método VPP     : ", _method);
   Print("VPP calculado  : $", DoubleToString(_vpp, 4), "/punto/lot");

   // Verificaciones críticas
   if(MathAbs(_vpp - 1.0) < 0.001)
      Print("✓ VPP = $1.00/pt/lot — CONFIRMADO (esperado para XAUUSD FundingPips)");
   else if(_vpp > 0)
      Print("⚠ VPP = $", DoubleToString(_vpp, 4), " — DIFERENTE AL ESPERADO ($1.00) — VERIFICAR");
   else
      Print("✗ ERROR: VPP = 0 — NO OPERAR hasta corregir");

   // Test de tamaños de SL con el VPP calculado
   Print("--- TABLA DE LOTAJE (Risk=$", RiskAmountUSD, ") ---");
   double slTests[] = {50.0, 100.0, 150.0, 200.0, 300.0, 400.0};
   for(int i = 0; i < ArraySize(slTests); i++)
   {
      double _slPts = slTests[i];
      double _slDist = _slPts * _pt;  // en precio
      double _lRaw  = RiskAmountUSD / (_slPts * _vpp);
      double _ls    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
      double _lNorm = MathMax(_mn, MathMin(5.0, MathFloor(_lRaw / _ls) * _ls));
      double _rReal = _slPts * _vpp * _lNorm;
      double _tp3   = _slPts * TP3_RR * _vpp * _lNorm;
      Print("  SL=", DoubleToString(_slPts, 0), "pts ($",
            DoubleToString(_slDist, _dg), ")",
            " → ", DoubleToString(_lNorm, 2), " lots",
            " | Risk=$", DoubleToString(_rReal, 2),
            " | TP3=$", DoubleToString(_tp3, 0));
   }

   //--- VERIFICACIÓN CON OrderCalcProfit ---
   // Esta es la VERDAD ABSOLUTA del broker
   // Si OrderCalcProfit(BUY, 1.0 lot, entrada, entrada-100pts) ≈ $100 → VPP=$1.00 ✓
   double _ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double _fromSL  = _ask - 100.0 * _pt; // SL a 100 puntos del ask
   double _profit  = 0;
   double _profTP  = 0;
   bool   _calcOK  = OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0, _fromSL, _ask, _profit);
   bool   _calcTP  = OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0, _ask, _ask + 300.0 * _pt, _profTP);
   Print("--- OrderCalcProfit VERIFICACIÓN ---");
   Print("Test BUY 1.0 lot, 100 puntos SL:");
   if(_calcOK)
   {
      Print("  Profit calculado : $", DoubleToString(_profit, 2));
      if(MathAbs(_profit - 100.0) < 1.0)
         Print("  ✓ VPP CONFIRMADO: $1.00/pt/lot por OrderCalcProfit");
      else
         Print("  ⚠ VPP DIVERGE: profit=$", DoubleToString(_profit, 2),
               " esperado=$100 — INVESTIGAR antes de operar");
   }
   else
      Print("  ✗ OrderCalcProfit FALLÓ — verificar manualmente");

   Print("Test BUY 1.0 lot, TP3 (300pts):");
   if(_calcTP)
      Print("  Profit TP3=300pts : $", DoubleToString(_profTP, 2),
            " (esperado ~$300 si vpp=$1.00)");
   Print("---------------------------------------------");

   // Configuración del EA
   Print("=== CONFIGURACIÓN EA ===");
   Print("MagicNumber    : ", MagicNumber,
         MagicNumber == 202404 ? " ✓" : " ⚠ NO es 202404");
   Print("Offset UTC     : ", ServerOffsetHours, "h");
   Print("Ventana        : 14:50 – 15:", StringFormat("%02d", EntryWindowEnd_Min), " UTC");
   Print("Cierre sesión  : ", SessionCloseHour, ":", StringFormat("%02d", SessionCloseMin), " UTC");
   Print("Riesgo         : $", RiskAmountUSD, " por trade");
   Print("Objetivos      : TP1=1:", TP1_RR, "  TP2=1:", TP2_RR, "  TP3=1:", TP3_RR);
   Print("Parciales      : ", EnablePartials ? "ACTIVOS" : "DESACTIVADOS (backtest base)");
   Print("BE_BufferPct   : ", BE_BufferPct, "% del SL → BE activa cuando recorre ",
         BE_BufferPct, "% hacia TP");
   Print("Filtros día    : L=", FilterMonday?"SI":"NO",
         " M=", FilterTuesday?"SI":"NO",
         " X=", FilterWednesday?"SI":"NO",
         " J=", FilterThursday?"SI":"NO",
         " V=", FilterFriday?"SI":"NO");
   Print("MinSL/MaxSL    : ", MinSL_Points, " / ", MaxSL_Points, " pts",
         " (PROVISIONAL — calibrar con historial)");
   Print("ConfirmOnClose : ", ConfirmOnClose ? "SI ✓" : "NO — ERROR, debe ser true");
   if(ATR_FilterEnable)
      Print("Filtro ATR     : ACTIVO | Período=", ATR_Period, " | Base=", ATR_BaselineDays, "días",
            " | Rango=[baseline×", ATR_MinMultiplier, " – baseline×", ATR_MaxMultiplier, "]",
            " | ⚠ MaxMult=", ATR_MaxMultiplier, " (vs 2.0 en DJI30 — más estricto)");
   else
      Print("Filtro ATR     : DESACTIVADO — ⚠ NO RECOMENDADO para XAUUSD");
   Print("==========================================================");

   // Advertencias de seguridad
   if(!ConfirmOnClose)
      Print("⚠ ADVERTENCIA CRÍTICA: ConfirmOnClose=false — RIESGO de false breakouts");
   if(SessionCloseHour > 17)
      Print("⚠ ADVERTENCIA: SessionCloseHour=", SessionCloseHour,
            " — riesgo de posiciones overnight");
   if(MathAbs(_vpp) < 0.0001)
      Print("✗ ERROR CRÍTICO: VPP=0 — el EA no calculará lotaje correctamente");
   if(!ATR_FilterEnable)
      Print("⚠ ADVERTENCIA: ATR_FilterEnable=false — XAUUSD requiere filtro ATR activo");

   VisRedrawAll();
   return INIT_SUCCEEDED;
}

//===================================================================
//  OnDeinit
//===================================================================

void OnDeinit(const int reason)
{
   if(csvHandle != INVALID_HANDLE)
   {
      FileFlush(csvHandle);
      FileClose(csvHandle);
      csvHandle = INVALID_HANDLE;
   }
   // Limpiar objetos visuales
   for(int i = ObjectsTotal(0, -1, -1) - 1; i >= 0; i--)
   {
      string name = ObjectName(0, i);
      if(StringFind(name, VIS_PFX) == 0)
         ObjectDelete(0, name);
   }
   ChartRedraw(0);
   Print("BreakoutNY XAUUSD v1.0 detenido. Razón=", reason);
}

//===================================================================
//  OnTradeTransaction — captura de cierres para CSV
//===================================================================

void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest    &request,
                        const MqlTradeResult     &result)
{
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD)
   {
      if(HistoryDealSelect(trans.deal))
      {
         ulong      dealMagic = HistoryDealGetInteger(trans.deal, DEAL_MAGIC);
         ENUM_DEAL_ENTRY entry = (ENUM_DEAL_ENTRY)HistoryDealGetInteger(trans.deal, DEAL_ENTRY);

         if(dealMagic == MagicNumber && entry == DEAL_ENTRY_OUT)
         {
            double exitPx  = HistoryDealGetDouble(trans.deal, DEAL_PRICE);
            double profit  = HistoryDealGetDouble(trans.deal, DEAL_PROFIT);
            double swap    = HistoryDealGetDouble(trans.deal, DEAL_SWAP);
            double commission = HistoryDealGetDouble(trans.deal, DEAL_COMMISSION);
            double total   = profit + swap + commission;

            stat_total++;
            if(total >= 0) { stat_wins++;   stat_grossProfit += total; }
            else            { stat_losses++; stat_grossLoss   += total; }

            WriteTradeRow(exitPx, total);

            Print("TRADE CERRADO XAUUSD | P&L=$", DoubleToString(total, 2),
                  " (profit=$", DoubleToString(profit, 2),
                  " swap=$", DoubleToString(swap, 2),
                  " comm=$", DoubleToString(commission, 2), ")");
         }
      }
   }
}

//===================================================================
//  OnTick — lógica principal
//===================================================================

void OnTick()
{
   int utcH, utcM;
   GetCurrentUTC(utcH, utcM);

   MqlDateTime sdt; TimeToStruct(TimeCurrent(), sdt);
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                 sdt.year, sdt.mon, sdt.day));

   //=== RESET DIARIO ================================================
   if(today != lastTradeDay)
   {
      DailyReset();
      lastTradeDay = today;
      vis_dayTag   = VisMakeDayTag();
      VisRedrawAll();
   }

   if(dayFiltered) return;

   //=== FILTRO: DÍA DE SEMANA =======================================
   if(!rangeCalculated && !dayFiltered && !tradeExecuted &&
      utcH == 14 && utcM >= 50)
   {
      if(!IsTradingDayAllowed())
      {
         dayFiltered = true; tradeExecuted = true;
         Print("DIA FILTRADO: ", WeekdayName(GetWeekdayUTC()));
         WriteFilteredRow("day");
         return;
      }
   }

   //=== PASO 1: CALCULAR RANGO (14:50 UTC) ==========================
   if(!rangeCalculated && !tradeExecuted && utcH == 14 && utcM >= 50)
   {
      double h35, l35, h40, l40, h45, l45;
      bool ok = GetCandleAtUTC(14, 35, h35, l35) &&
                GetCandleAtUTC(14, 40, h40, l40) &&
                GetCandleAtUTC(14, 45, h45, l45);
      if(!ok) { Print("AVISO: Velas del rango no encontradas."); return; }

      rangeHigh  = MathMax(h35, MathMax(h40, h45));
      rangeLow   = MathMin(l35, MathMin(l40, l45));
      slDistance = rangeHigh - rangeLow;            // en precio (ej. 1.50 = 150 puntos a 0.01)
      double slPts = slDistance / _Point;            // puntos reales del instrumento

      // ── Filtro ATR ───────────────────────────────────────────────
      if(ATR_FilterEnable)
      {
         int atrHandle = iATR(_Symbol, PERIOD_M5, ATR_Period);
         if(atrHandle != INVALID_HANDLE)
         {
            double atrNow[1];
            CopyBuffer(atrHandle, 0, 1, 1, atrNow);
            double currentATR = atrNow[0] / _Point;

            int barsBaseline = ATR_BaselineDays * 24 * 12;
            double atrBuf[];
            ArrayResize(atrBuf, barsBaseline);
            int copied = CopyBuffer(atrHandle, 0, 1, barsBaseline, atrBuf);
            IndicatorRelease(atrHandle);

            if(copied > 10)
            {
               double sum = 0;
               for(int ai = 0; ai < copied; ai++) sum += atrBuf[ai];
               double baselineATR = (sum / copied) / _Point;

               double atrMin = baselineATR * ATR_MinMultiplier;
               double atrMax = baselineATR * ATR_MaxMultiplier;

               if(currentATR < atrMin || currentATR > atrMax)
               {
                  rangeFiltered = true; tradeExecuted = true;
                  Print("ATR FILTRADO XAUUSD: ATR=", DoubleToString(currentATR, 1),
                        "pts | Baseline=", DoubleToString(baselineATR, 1),
                        "pts | Rango=[", DoubleToString(atrMin, 1),
                        "-", DoubleToString(atrMax, 1), "]");
                  WriteFilteredRow("atr");
                  return;
               }
               else
                  Print("ATR OK XAUUSD: ", DoubleToString(currentATR, 1),
                        "pts | Baseline=", DoubleToString(baselineATR, 1),
                        "pts | Rango=[", DoubleToString(atrMin, 1),
                        "-", DoubleToString(atrMax, 1), "]");
            }
         }
      }

      // ── Filtro rango MinSL/MaxSL ─────────────────────────────────
      bool tooLarge = (MaxSL_Points > 0 && slPts > MaxSL_Points);
      bool tooSmall = (MinSL_Points > 0 && slPts < MinSL_Points);

      if(tooLarge || tooSmall)
      {
         rangeFiltered = true; tradeExecuted = true;
         log_SL_Pts    = slDistance;
         log_Weekday   = WeekdayName(GetWeekdayUTC());
         Print("RANGO FILTRADO XAUUSD: ", DoubleToString(slPts, 1), " pts ($",
               DoubleToString(slDistance, _Digits), ")",
               " | Filtro: [", MinSL_Points, "-", MaxSL_Points, " pts]",
               tooSmall ? " → DEMASIADO PEQUEÑO" : " → DEMASIADO GRANDE");
         WriteFilteredRow("range");
         return;
      }

      rangeCalculated = true;
      log_RangeHigh   = rangeHigh;
      log_RangeLow    = rangeLow;
      cachedLots      = CalculateLotSize(slDistance);

      // ── Filtro TF (desactivado por defecto) ──────────────────────
      if(TF_Enable)
      {
         double rangeMid = (rangeHigh + rangeLow) / 2.0;
         CalcTrendFilter(rangeMid);
         if(tf_allowedDir == "none")
         {
            rangeFiltered = true; tradeExecuted = true;
            Print("TF ZONA NEUTRA XAUUSD: no se opera | mid=",
                  DoubleToString(rangeMid, _Digits),
                  " prevClose=", DoubleToString(tf_prevClose, _Digits));
            WriteFilteredRow("tf");
            return;
         }
      }
      else tf_allowedDir = "both";

      Print("Rango OK XAUUSD: H=", DoubleToString(rangeHigh, _Digits),
            " L=", DoubleToString(rangeLow, _Digits),
            " SL=", DoubleToString(slPts, 1), "pts ($",
            DoubleToString(slDistance, _Digits), ")",
            " | Lots=", DoubleToString(cachedLots, 2),
            " | ConfirmOnClose=", ConfirmOnClose ? "SI" : "NO");

      VisRedrawToday();
   }

   //=== PASO 2: BUSCAR ENTRADA =======================================
   if(rangeCalculated && !tradeExecuted)
   {
      bool inWindow;
      if(EntryWindowEnd_Min >= 50)
         inWindow = (utcH == 14 && utcM >= 50 && utcM <= EntryWindowEnd_Min);
      else
         inWindow = (utcH == 14 && utcM >= 50) ||
                    (utcH == 15 && utcM <= EntryWindowEnd_Min);

      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);

      //--- FASE A: Detección de ruptura ---
      if(inWindow && !HasOpenPosition() && !breakoutPending)
      {
         if(ask > rangeHigh)  // Candidato BUY
         {
            if(TF_Enable && tf_allowedDir == "sell")
            {
               Print("TF: BUY bloqueado (dir=SELL)");
               tradeExecuted = true; WriteFilteredRow("tf"); return;
            }
            if(!ConfirmOnClose)
            {
               double lots = cachedLots;
               if(lots <= 0) { Print("ERROR: Lotaje 0."); return; }
               double sl = NormalizeDouble(ask - slDistance, _Digits);
               double tp = NormalizeDouble(ask + slDistance * TP3_RR, _Digits);
               if(trade.Buy(lots, _Symbol, ask, sl, tp, "BreakoutNY XAUUSD BUY"))
               {
                  tradeExecuted = true;
                  entryPrice = ask;  originalSL = sl;
                  originalLots = lots; tradeDir = "buy";
                  activeTicket = trade.ResultOrder();
                  tp1Price = NormalizeDouble(ask + slDistance * TP1_RR, _Digits);
                  tp2Price = NormalizeDouble(ask + slDistance * TP2_RR, _Digits);
                  tp3Price = NormalizeDouble(ask + slDistance * TP3_RR, _Digits);
                  bePrice  = NormalizeDouble(ask + slDistance * (BE_BufferPct / 100.0), _Digits);
                  log_OpenTime  = TimeCurrent(); log_Weekday = WeekdayName(GetWeekdayUTC());
                  log_SL_Pts    = slDistance;    log_ConfirmUsed = false;
                  Print(">>> BUY XAUUSD (inmediato) Entry=", DoubleToString(ask, _Digits),
                        " SL=", DoubleToString(sl, _Digits),
                        " TP3=", DoubleToString(tp3Price, _Digits),
                        " Lots=", DoubleToString(lots, 2));
                  vis_hasTrade = true; VisRedrawToday();
               }
            }
            else
            {
               breakoutPending = true;
               pendingDir      = "buy";
               pendingBarTime  = currentBarTime;
               Print(">>> BUY XAUUSD pendiente confirmación | vela=",
                     TimeToString(currentBarTime, TIME_DATE | TIME_MINUTES),
                     " | ask=", DoubleToString(ask, _Digits),
                     " rangeHigh=", DoubleToString(rangeHigh, _Digits));
            }
         }
         else if(bid < rangeLow)  // Candidato SELL
         {
            if(TF_Enable && tf_allowedDir == "buy")
            {
               Print("TF: SELL bloqueado (dir=BUY)");
               tradeExecuted = true; WriteFilteredRow("tf"); return;
            }
            if(!ConfirmOnClose)
            {
               double lots = cachedLots;
               if(lots <= 0) { Print("ERROR: Lotaje 0."); return; }
               double sl = NormalizeDouble(bid + slDistance, _Digits);
               double tp = NormalizeDouble(bid - slDistance * TP3_RR, _Digits);
               if(trade.Sell(lots, _Symbol, bid, sl, tp, "BreakoutNY XAUUSD SELL"))
               {
                  tradeExecuted = true;
                  entryPrice = bid;  originalSL = sl;
                  originalLots = lots; tradeDir = "sell";
                  activeTicket = trade.ResultOrder();
                  tp1Price = NormalizeDouble(bid - slDistance * TP1_RR, _Digits);
                  tp2Price = NormalizeDouble(bid - slDistance * TP2_RR, _Digits);
                  tp3Price = NormalizeDouble(bid - slDistance * TP3_RR, _Digits);
                  bePrice  = NormalizeDouble(bid - slDistance * (BE_BufferPct / 100.0), _Digits);
                  log_OpenTime  = TimeCurrent(); log_Weekday = WeekdayName(GetWeekdayUTC());
                  log_SL_Pts    = slDistance;    log_ConfirmUsed = false;
                  Print(">>> SELL XAUUSD (inmediato) Entry=", DoubleToString(bid, _Digits),
                        " SL=", DoubleToString(sl, _Digits),
                        " TP3=", DoubleToString(tp3Price, _Digits),
                        " Lots=", DoubleToString(lots, 2));
                  vis_hasTrade = true; VisRedrawToday();
               }
            }
            else
            {
               breakoutPending = true;
               pendingDir      = "sell";
               pendingBarTime  = currentBarTime;
               Print(">>> SELL XAUUSD pendiente confirmación | vela=",
                     TimeToString(currentBarTime, TIME_DATE | TIME_MINUTES),
                     " | bid=", DoubleToString(bid, _Digits),
                     " rangeLow=", DoubleToString(rangeLow, _Digits));
            }
         }
      }

      //--- FASE B: Confirmación (cierre de vela) ---
      if(breakoutPending && !tradeExecuted && !HasOpenPosition() &&
         currentBarTime > pendingBarTime)
      {
         bool stillValid = false;
         if(pendingDir == "buy"  && ask > rangeHigh) stillValid = true;
         if(pendingDir == "sell" && bid < rangeLow)  stillValid = true;

         if(!stillValid)
         {
            Print(">>> Breakout CANCELADO XAUUSD: la vela cerró de vuelta al rango. ",
                  "Dir=", pendingDir,
                  " ask=", DoubleToString(ask, _Digits),
                  " bid=", DoubleToString(bid, _Digits),
                  " rangeHigh=", DoubleToString(rangeHigh, _Digits),
                  " rangeLow=", DoubleToString(rangeLow, _Digits));
            breakoutPending = false;
            pendingDir      = "";
            pendingBarTime  = 0;
         }
         else
         {
            double lots = cachedLots;
            if(lots <= 0) { Print("ERROR: Lotaje 0."); return; }

            if(pendingDir == "buy")
            {
               double sl = NormalizeDouble(ask - slDistance, _Digits);
               double tp = NormalizeDouble(ask + slDistance * TP3_RR, _Digits);
               if(trade.Buy(lots, _Symbol, ask, sl, tp, "BreakoutNY XAUUSD BUY"))
               {
                  tradeExecuted   = true;
                  breakoutPending = false;
                  entryPrice = ask; originalSL = sl;
                  originalLots = lots; tradeDir = "buy";
                  activeTicket = trade.ResultOrder();
                  tp1Price = NormalizeDouble(ask + slDistance * TP1_RR, _Digits);
                  tp2Price = NormalizeDouble(ask + slDistance * TP2_RR, _Digits);
                  tp3Price = NormalizeDouble(ask + slDistance * TP3_RR, _Digits);
                  bePrice  = NormalizeDouble(ask + slDistance * (BE_BufferPct / 100.0), _Digits);
                  log_OpenTime    = TimeCurrent(); log_Weekday = WeekdayName(GetWeekdayUTC());
                  log_SL_Pts      = slDistance;    log_ConfirmUsed = true;
                  Print(">>> BUY CONFIRMADO XAUUSD Entry=", DoubleToString(ask, _Digits),
                        " SL=", DoubleToString(sl, _Digits),
                        " TP3=", DoubleToString(tp3Price, _Digits),
                        " Lots=", DoubleToString(lots, 2),
                        " | esperó vela ", TimeToString(pendingBarTime, TIME_DATE | TIME_MINUTES));
                  vis_hasTrade = true; VisRedrawToday();
               }
            }
            else // sell
            {
               double sl = NormalizeDouble(bid + slDistance, _Digits);
               double tp = NormalizeDouble(bid - slDistance * TP3_RR, _Digits);
               if(trade.Sell(lots, _Symbol, bid, sl, tp, "BreakoutNY XAUUSD SELL"))
               {
                  tradeExecuted   = true;
                  breakoutPending = false;
                  entryPrice = bid; originalSL = sl;
                  originalLots = lots; tradeDir = "sell";
                  activeTicket = trade.ResultOrder();
                  tp1Price = NormalizeDouble(bid - slDistance * TP1_RR, _Digits);
                  tp2Price = NormalizeDouble(bid - slDistance * TP2_RR, _Digits);
                  tp3Price = NormalizeDouble(bid - slDistance * TP3_RR, _Digits);
                  bePrice  = NormalizeDouble(bid - slDistance * (BE_BufferPct / 100.0), _Digits);
                  log_OpenTime    = TimeCurrent(); log_Weekday = WeekdayName(GetWeekdayUTC());
                  log_SL_Pts      = slDistance;    log_ConfirmUsed = true;
                  Print(">>> SELL CONFIRMADO XAUUSD Entry=", DoubleToString(bid, _Digits),
                        " SL=", DoubleToString(sl, _Digits),
                        " TP3=", DoubleToString(tp3Price, _Digits),
                        " Lots=", DoubleToString(lots, 2),
                        " | esperó vela ", TimeToString(pendingBarTime, TIME_DATE | TIME_MINUTES));
                  vis_hasTrade = true; VisRedrawToday();
               }
            }
         }
      }

      // Ventana cerrada sin entrada
      if(!inWindow && !HasOpenPosition() && !breakoutPending && !tradeExecuted)
      {
         tradeExecuted = true;
         Print("Ventana cerrada sin breakout XAUUSD.");
         VisRedrawToday();
      }
      if(!inWindow && breakoutPending && !tradeExecuted)
      {
         Print("Ventana cerrada con breakout pendiente sin confirmar XAUUSD. Dir=", pendingDir);
         breakoutPending = false;
         tradeExecuted   = true;
         VisRedrawToday();
      }
   }

   //=== PASO 3: GESTIÓN DE PARCIALES Y BE ===========================
   if(tradeExecuted && HasOpenPosition() && EnablePartials && entryPrice > 0)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      //--- FASE 1: TP1 → cierre parcial + activar BE ---------------
      if(!phase1Done)
      {
         bool tp1Hit = (tradeDir == "buy"  && bid >= tp1Price) ||
                       (tradeDir == "sell" && ask <= tp1Price);
         if(tp1Hit)
         {
            phase1Done    = true;
            log_Phase1Hit = true;

            double lotsToClose = 0;
            if(TP1_ClosePct > 0)
            {
               lotsToClose = NormalizeLots(originalLots * TP1_ClosePct / 100.0);
               if(lotsToClose >= GetPositionLots()) lotsToClose = 0;
            }
            if(lotsToClose > 0)
            {
               ulong tk = GetPositionTicket();
               if(ClosePartial(tk, lotsToClose))
                  Print("FASE 1 XAUUSD: Cerrado ", lotsToClose, " lotes en TP1");
               else
                  Print("FASE 1 XAUUSD: Error cierre parcial: ", GetLastError());
            }
            if(ModifySL(bePrice))
            {
               Print("FASE 1 XAUUSD: BE activado → SL=", DoubleToString(bePrice, _Digits));
               if(VIS_Enable && vis_dayTag != "")
                  VisMoveLevel(VIS_PFX + "SL_" + vis_dayTag, bePrice);
            }
            else
               Print("FASE 1 XAUUSD: Error al activar BE: ", GetLastError());
         }
      }

      //--- FASE 2: TP2 → cierre parcial + SL a TP1 -----------------
      if(phase1Done && !phase2Done)
      {
         bool tp2Hit = (tradeDir == "buy"  && bid >= tp2Price) ||
                       (tradeDir == "sell" && ask <= tp2Price);
         if(tp2Hit)
         {
            phase2Done    = true;
            log_Phase2Hit = true;

            double lotsToClose = 0;
            if(TP2_ClosePct > 0)
            {
               lotsToClose = NormalizeLots(originalLots * TP2_ClosePct / 100.0);
               double curLots = GetPositionLots();
               double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
               if(curLots - lotsToClose < minLot)
                  lotsToClose = NormalizeLots(curLots - minLot);
               if(lotsToClose < minLot) lotsToClose = 0;
            }
            if(lotsToClose > 0)
            {
               ulong tk = GetPositionTicket();
               if(ClosePartial(tk, lotsToClose))
                  Print("FASE 2 XAUUSD: Cerrado ", lotsToClose, " lotes en TP2");
               else
                  Print("FASE 2 XAUUSD: Error cierre parcial: ", GetLastError());
            }
            if(ModifySL(tp1Price))
            {
               Print("FASE 2 XAUUSD: SL → TP1=", DoubleToString(tp1Price, _Digits));
               if(VIS_Enable && vis_dayTag != "")
                  VisMoveLevel(VIS_PFX + "SL_" + vis_dayTag, tp1Price);
            }
            else
               Print("FASE 2 XAUUSD: Error al mover SL a TP1: ", GetLastError());
         }
      }
   }

   //=== PASO 4: BE SIMPLE (sin parciales) ===========================
   // Cuando EnablePartials=false pero queremos activar el BE
   if(tradeExecuted && HasOpenPosition() && !EnablePartials && entryPrice > 0 && !phase1Done)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      bool beHit = (tradeDir == "buy"  && bid >= bePrice) ||
                   (tradeDir == "sell" && ask <= bePrice);
      if(beHit)
      {
         phase1Done    = true;
         log_Phase1Hit = true;
         double bePriceActual = NormalizeDouble(entryPrice + (tradeDir == "buy" ? 0 : 0), _Digits);
         // BE mueve SL a entry (riesgo 0)
         bePriceActual = entryPrice;
         if(ModifySL(bePriceActual))
         {
            log_BE_Activated = true;
            Print("BE XAUUSD activado → SL a entry=", DoubleToString(bePriceActual, _Digits));
            if(VIS_Enable && vis_dayTag != "")
               VisMoveLevel(VIS_PFX + "SL_" + vis_dayTag, bePriceActual);
         }
      }
   }

   //=== PASO 5: CIERRE AL FINAL DE SESIÓN ===========================
   bool pastCloseTime;
   if(SessionCloseMin == 0)
      pastCloseTime = (utcH >= SessionCloseHour);
   else
      pastCloseTime = (utcH > SessionCloseHour) ||
                      (utcH == SessionCloseHour && utcM >= SessionCloseMin);

   if(pastCloseTime && HasOpenPosition())
   {
      Print("Fin de sesión XAUUSD (", SessionCloseHour, ":",
            StringFormat("%02d", SessionCloseMin), " UTC) — cerrando posición.");
      CloseAll();
   }
}
