   }
}

//===================================================================
//  CÁLCULO DE LOTAJE — XAUUSD ADAPTADO
//===================================================================
//
//  XAUUSD en FundingPips:
//    ContractSize = 100 oz
//    TickSize     = 0.01
//    TickValue    = 0.01
//    Point        = 0.01
//
//  Cascada de cálculo VPP:
//    Método 1 (estándar): tv/ts = 0.01/0.01 = $1.00/punto/lot
//    Método 2 (fallback): ContractSize × Point = 100 × 0.01 = $1.00/punto/lot
//    ✓ Ambos métodos dan el mismo resultado para XAUUSD — consistencia alta
//
//  Verificación con OrderCalcProfit:
//    Si SL = 100 puntos y Risk = $50 → Lots = 50/(100×1.00) = 0.50 lots
//    RiskReal = 100 × 1.00 × 0.50 = $50.00 ✓
//
//  DIFERENCIA vs DJI30:
//    DJI30: vpp=$0.05/pt/lot → $50 riesgo con SL=100pts → 10 lots
//    XAUUSD: vpp=$1.00/pt/lot → $50 riesgo con SL=100pts → 0.5 lots
//    → MUCHO mayor VPP en XAUUSD — movimientos pequeños = riesgo alto
//
double CalculateLotSize(double slDistance_price)
{
   //--- slDistance_price está en precio (ej. 1.50 para SL de 150 puntos a 0.01 point)
   //--- Lo convertimos a puntos reales para el cálculo
   double slPoints = slDistance_price / _Point;  // puntos reales del instrumento

   if(slPoints <= 0) return 0;

   double tv = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double ts = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double cs = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double ls = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double mn = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double mx = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

   // Forzar VolumeMax a 5 para FundingPips XAUUSD
   // (el broker limita a 5 lotes por operación en este instrumento)
   mx = MathMin(mx, 5.0);

   double valuePerPoint = 0;

   // MÉTODO 1: Broker reporta TickValue y TickSize correctos
   // Para XAUUSD FundingPips: tv=0.01, ts=0.01 → vpp = 0.01/0.01 = $1.00/pt/lot
   if(tv > 0 && ts > 0)
   {
      valuePerPoint = tv / ts;
      Print("VPP Método 1 (tv/ts): $", DoubleToString(valuePerPoint, 4), "/pt/lot");
   }
   // MÉTODO 2: Fallback ContractSize × Point
   // Para XAUUSD: 100 × 0.01 = $1.00/pt/lot → mismo resultado que Método 1
   else if(cs > 0 && pt > 0)
   {
      valuePerPoint = cs * pt;
      Print("VPP Método 2 (CS×Pt FALLBACK): $", DoubleToString(valuePerPoint, 4), "/pt/lot");
   }
   else
   {
      Print("ERROR LotCalc: Datos insuficientes. TV=", tv, " TS=", ts, " CS=", cs, " PT=", pt,
            ". Usando lote mínimo.");
      return mn;
   }

   if(valuePerPoint <= 0)
   {
      Print("ERROR LotCalc: valuePerPoint=0. Usando lote mínimo.");
      return mn;
   }

   // LOTAJE DINÁMICO: Lots = RiskUSD / (SL_pts × $/pt/lot)
   double lotsRaw = RiskAmountUSD / (slPoints * valuePerPoint);
   double lots    = MathFloor(lotsRaw / ls) * ls;
   lots           = MathMax(mn, MathMin(mx, lots));

   double realRisk = slPoints * valuePerPoint * lots;

   log_ValuePerPoint = valuePerPoint;
   log_RiskReal_USD  = realRisk;

   // Verificación de margen disponible
   double freeMargin   = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   double marginPerLot = 0;
   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, 1.0,
                       SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginPerLot))
      marginPerLot = SymbolInfoDouble(_Symbol, SYMBOL_ASK) * cs * 0.01; // 1% margin estimate

   if(marginPerLot > 0)
   {
      double maxLotsByMargin = MathFloor((freeMargin * 0.90) / marginPerLot / ls) * ls;
      maxLotsByMargin = MathMax(mn, MathMin(mx, maxLotsByMargin));
      if(lots > maxLotsByMargin)
      {
         Print("AVISO Margen: lots=", DoubleToString(lots, 2),
               " excede margen libre=$", DoubleToString(freeMargin, 2),
               " (max=", DoubleToString(maxLotsByMargin, 2), " lots).",
               " Reduciendo a ", DoubleToString(maxLotsByMargin, 2));
         lots     = maxLotsByMargin;
         realRisk = slPoints * valuePerPoint * lots;
         log_RiskReal_USD = realRisk;
      }
   }

   log_LotsCalculated = lotsRaw;

   Print("LotCalc XAUUSD | SL=", DoubleToString(slPoints, 1), "pts ($",
         DoubleToString(slDistance_price, _Digits), ")",
         " | vpp=$", DoubleToString(valuePerPoint, 4), "/pt/lot",
         " | RiskUSD=$", RiskAmountUSD,
         " | Raw=", DoubleToString(lotsRaw, 4),
         " | Lots=", DoubleToString(lots, 2),
         " | RiskReal=$", DoubleToString(realRisk, 2),
         " | Margin/lot=$", DoubleToString(marginPerLot, 2),
         " | FreeMargin=$", DoubleToString(freeMargin, 2));

   return lots;
}

double NormalizeLots(double lots)
{
   double ls = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double mn = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double mx = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 5.0);
   lots = MathFloor(lots / ls) * ls;
   return MathMax(mn, MathMin(mx, lots));
}

