bool GetCandleAtUTC(int h, int m, double &high, double &low)
{
   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   if(CopyRates(_Symbol, PERIOD_M5, 0, 100, rates) <= 0) return false;
   for(int i = 0; i < ArraySize(rates); i++)
   {
      MqlDateTime dt;
      TimeToStruct(rates[i].time - (long)ServerOffsetHours * 3600, dt);
      if(dt.hour == h && dt.min == m)
      {
         high = rates[i].high;
         low  = rates[i].low;
         return true;
      }
   }
   return false;
}

bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == _Symbol && posInfo.Magic() == MagicNumber)
            return true;
   return false;
}

double GetPositionLots()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == _Symbol && posInfo.Magic() == MagicNumber)
            return posInfo.Volume();
   return 0;
}

ulong GetPositionTicket()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == _Symbol && posInfo.Magic() == MagicNumber)
            return posInfo.Ticket();
   return 0;
}

double GetPositionProfit()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == _Symbol && posInfo.Magic() == MagicNumber)
            return posInfo.Profit();
   return 0;
}

bool ModifySL(double newSL)
{
   ulong tk = GetPositionTicket();
   if(tk == 0) return false;
   if(!posInfo.SelectByTicket(tk)) return false;
   double tp = posInfo.TakeProfit();
   return trade.PositionModify(tk, NormalizeDouble(newSL, _Digits), tp);
}

bool ClosePartial(ulong ticket, double lotsToClose)
{
   return trade.PositionClosePartial(ticket, lotsToClose);
}

void CloseAll()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == _Symbol && posInfo.Magic() == MagicNumber)
         {
            log_SL_Final     = posInfo.StopLoss();
            log_BE_Activated = (posInfo.StopLoss() >= entryPrice && tradeDir == "buy") ||
                               (posInfo.StopLoss() <= entryPrice && tradeDir == "sell" && entryPrice > 0);
            trade.PositionClose(posInfo.Ticket());
         }
   }
}

//===================================================================
//  FILTRO DE TENDENCIA INTRADIARIA (experimental — desactivado)
//===================================================================

void CalcTrendFilter(double midRange)
{
   tf_midRange = midRange;
   if(tf_prevClose <= 0) { tf_allowedDir = "both"; return; }

   double threshold = TF_Threshold_Pts * _Point;

   if(midRange > tf_prevClose + threshold)
      tf_allowedDir = "buy";
   else if(midRange < tf_prevClose - threshold)
      tf_allowedDir = "sell";
   else
   {
      tf_allowedDir = TF_BlockNeutral ? "none" : "both";
   }

   Print("TF | mid=", DoubleToString(midRange, _Digits),
         " prevClose=", DoubleToString(tf_prevClose, _Digits),
         " threshold=±", DoubleToString(TF_Threshold_Pts, 1),
         " → dir=", tf_allowedDir);
}

