         {
            MqlDateTime dt;
            TimeToStruct(rates[i].time - (long)ServerOffsetHours * 3600, dt);
            // Buscamos la última vela del día anterior que sea ≤ 16:55 UTC
            if(dt.hour <= 16 && !(dt.hour == 16 && dt.min > 55))
            {
               tf_prevClose = rates[i].close;
               break;
            }
         }
      }
   }
}

