void InitCSV()
{
   if(!EnableCSV) return;
   string fname = CSVFileName + ".csv";
   csvHandle = FileOpen(fname, FILE_WRITE | FILE_CSV | FILE_ANSI, ',');
   if(csvHandle == INVALID_HANDLE)
   {
      Print("ERROR: No se pudo abrir CSV: ", fname, " Error=", GetLastError());
      return;
   }
   // Cabecera
   FileWrite(csvHandle,
      "Date", "Weekday", "Direction", "EntryPrice", "ExitPrice",
      "SL_pts", "SL_price", "BE_price", "TP1", "TP2", "TP3",
      "Lots", "VPP", "LotsRaw", "RiskReal_USD",
      "RangeHigh", "RangeLow",
      "Phase1Hit", "Phase2Hit", "BE_Activated",
      "ConfirmUsed", "Result_USD", "FilterType",
      "FinalSL");
   Print("CSV iniciado: ", fname);
}

void WriteTradeRow(double exitPrice, double resultUSD)
{
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;
   double slPts   = log_SL_Pts / _Point;
   double slPrice = (tradeDir == "buy") ? entryPrice - log_SL_Pts : entryPrice + log_SL_Pts;

   FileWrite(csvHandle,
      TimeToString(log_OpenTime, TIME_DATE),
      log_Weekday,
      tradeDir,
      DoubleToString(entryPrice, _Digits),
      DoubleToString(exitPrice, _Digits),
      DoubleToString(slPts, 1),
      DoubleToString(slPrice, _Digits),
      DoubleToString(bePrice, _Digits),
      DoubleToString(tp1Price, _Digits),
      DoubleToString(tp2Price, _Digits),
      DoubleToString(tp3Price, _Digits),
      DoubleToString(originalLots, 2),
      DoubleToString(log_ValuePerPoint, 4),
      DoubleToString(log_LotsCalculated, 4),
      DoubleToString(log_RiskReal_USD, 2),
      DoubleToString(log_RangeHigh, _Digits),
      DoubleToString(log_RangeLow, _Digits),
      log_Phase1Hit ? "1" : "0",
      log_Phase2Hit ? "1" : "0",
      log_BE_Activated ? "1" : "0",
      log_ConfirmUsed ? "1" : "0",
      DoubleToString(resultUSD, 2),
      "",
      DoubleToString(log_SL_Final, _Digits));
   FileFlush(csvHandle);
}

void WriteFilteredRow(string filterType)
{
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;

   MqlDateTime dt;
   TimeToStruct(TimeCurrent() - (long)ServerOffsetHours * 3600, dt);
   string dateStr = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);

   FileWrite(csvHandle,
      dateStr,
      WeekdayName(GetWeekdayUTC()),
      "FILTERED",
      "", "", "",
      DoubleToString(log_SL_Pts / _Point, 1),
      "", "", "", "", "",
      "", "", "", "", "", "",
      "", "", "", "", "", filterType, "");
   FileFlush(csvHandle);
}

