//+------------------------------------------------------------------+
//|                          BreakoutNY_Calibrator_XAUUSD.mq5       |
//|           Script de calibración de rangos pre-NY para XAUUSD    |
//|                                                                   |
//|  INSTRUCCIONES DE USO:                                           |
//|  1. Compilar y ejecutar en gráfico XAUUSD M5                    |
//|  2. Período: mínimo 2021.01.01 → presente (historial M5 cargado)|
//|  3. El script imprime en el Diario los percentiles del rango     |
//|  4. P50 → usar como MinSL_Points en el EA                       |
//|  5. P90 → usar como MaxSL_Points (o P75 si P90 parece extremo)  |
//|                                                                   |
//|  DIFERENCIA vs DJI30 Calibrator:                                 |
//|  · Usa P50 como MinSL (no P25) — XAUUSD tiene rangos pre-NY     |
//|    más amplios y necesita filtro más conservador                 |
//|  · Incluye análisis por día de semana para identificar lunes     |
//|    (gaps) y viernes (cierre especulativo) si son outliers        |
//|  · Spread estimado: 20-50 pts → incluido en análisis de RR real |
//+------------------------------------------------------------------+
#property script_show_inputs
#property strict

input datetime StartDate    = __DATE__ - 365 * 5 * 86400; // 5 años atrás por defecto
input datetime EndDate      = __DATE__;                    // Hasta hoy
input int      ServerOffset = 2;                           // UTC+2 FundingPips
input double   SpreadEstPts = 30.0;                       // Spread estimado XAUUSD en puntos (30 pts = $0.30/lot)

void OnStart()
{
   Print("=======================================================");
   Print("=== BreakoutNY Calibrador XAUUSD — Rangos Pre-NY ===");
   Print("=======================================================");
   Print("Símbolo   : ", _Symbol);
   Print("Período   : ", TimeToString(StartDate, TIME_DATE),
         " → ", TimeToString(EndDate, TIME_DATE));
   Print("Offset UTC: +", ServerOffset, "h");
   Print("Spread est: ~", SpreadEstPts, " puntos");

   if(_Symbol != "XAUUSD" && StringFind(_Symbol, "XAU") < 0 &&
      StringFind(_Symbol, "GOLD") < 0)
      Print("⚠ ADVERTENCIA: El símbolo no parece ser XAUUSD. Verificar.");

   MqlRates rates[];
   ArraySetAsSeries(rates, false);  // orden cronológico

   datetime fetchFrom = StartDate - (datetime)5 * 86400; // buffer de 5 días
   int copied = CopyRates(_Symbol, PERIOD_M5, fetchFrom, EndDate, rates);
   if(copied <= 0)
   {
      Print("ERROR: No se pudieron obtener datos M5. Intentando con datos disponibles...");
      copied = CopyRates(_Symbol, PERIOD_M5, 0, 100000, rates);
      if(copied <= 0) { Print("ERROR CRÍTICO: Sin datos M5."); return; }
   }
   Print("Velas M5 cargadas: ", copied);

   // Almacenamiento de rangos diarios
   double ranges[];
   string dates[];
   int    weekdays[];
   ArrayResize(ranges,   0);
   ArrayResize(dates,    0);
   ArrayResize(weekdays, 0);

   // Para el análisis día × día
   double rangesByDay[7][];  // índice 0=Dom, 1=Lun, ... 5=Vie, 6=Sáb
   for(int d = 0; d < 7; d++) ArrayResize(rangesByDay[d], 0);

   datetime processedDay = 0;
   double h35_g=0, l35_g=0, h40_g=0, l40_g=0, h45_g=0, l45_g=0;
   bool   found35=false, found40=false, found45=false;
   int    currentDayOfWeek = 0;
   string currentDateStr   = "";

   for(int i = 0; i < copied; i++)
   {
      MqlDateTime dt;
      TimeToStruct(rates[i].time - (long)ServerOffset * 3600, dt);

      // Nueva fecha UTC
      datetime thisDay = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                         dt.year, dt.mon, dt.day));

      if(thisDay != processedDay)
      {
         // Procesar el día anterior
         if(found35 && found40 && found45 && processedDay >= StartDate)
         {
            double rHigh = MathMax(h35_g, MathMax(h40_g, h45_g));
            double rLow  = MathMin(l35_g, MathMin(l40_g, l45_g));
            double rng   = (rHigh - rLow) / _Point;

            if(rng > 0)
            {
               int sz = ArraySize(ranges);
               ArrayResize(ranges,   sz + 1);
               ArrayResize(dates,    sz + 1);
               ArrayResize(weekdays, sz + 1);
               ranges[sz]   = rng;
               dates[sz]    = currentDateStr;
               weekdays[sz] = currentDayOfWeek;

               int dIdx = currentDayOfWeek;
               int dSz  = ArraySize(rangesByDay[dIdx]);
               ArrayResize(rangesByDay[dIdx], dSz + 1);
               rangesByDay[dIdx][dSz] = rng;
            }
         }

         // Reset para nuevo día
         found35 = false; found40 = false; found45 = false;
         processedDay    = thisDay;
         currentDayOfWeek = dt.day_of_week;
         currentDateStr  = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
      }

      // Capturar velas 14:35, 14:40, 14:45 UTC
      if(dt.hour == 14 && dt.min == 35) { h35_g = rates[i].high; l35_g = rates[i].low; found35 = true; }
      if(dt.hour == 14 && dt.min == 40) { h40_g = rates[i].high; l40_g = rates[i].low; found40 = true; }
      if(dt.hour == 14 && dt.min == 45) { h45_g = rates[i].high; l45_g = rates[i].low; found45 = true; }
   }

   // Procesar último día
   if(found35 && found40 && found45 && processedDay >= StartDate)
   {
      double rHigh = MathMax(h35_g, MathMax(h40_g, h45_g));
      double rLow  = MathMin(l35_g, MathMin(l40_g, l45_g));
      double rng   = (rHigh - rLow) / _Point;
      if(rng > 0)
      {
         int sz = ArraySize(ranges);
         ArrayResize(ranges,   sz + 1);
         ArrayResize(dates,    sz + 1);
         ArrayResize(weekdays, sz + 1);
         ranges[sz]   = rng;
         dates[sz]    = currentDateStr;
         weekdays[sz] = currentDayOfWeek;
      }
   }

   int total = ArraySize(ranges);
   if(total < 10)
   {
      Print("ERROR: Solo ", total, " días válidos encontrados. Necesita más historial.");
      return;
   }

   // Ordenar para percentiles
   double sorted[];
   ArrayCopy(sorted, ranges);
   ArraySort(sorted);

   // Calcular estadísticas globales
   double sumR = 0, minR = sorted[0], maxR = sorted[total - 1];
   for(int i = 0; i < total; i++) sumR += sorted[i];
   double meanR  = sumR / total;
   double medR   = sorted[(int)(total * 0.50)];

   double p10    = sorted[(int)(total * 0.10)];
   double p15    = sorted[(int)(total * 0.15)];
   double p20    = sorted[(int)(total * 0.20)];
   double p25    = sorted[(int)(total * 0.25)];
   double p50    = sorted[(int)(total * 0.50)];
   double p60    = sorted[(int)(total * 0.60)];
   double p70    = sorted[(int)(total * 0.70)];
   double p75    = sorted[(int)(total * 0.75)];
   double p80    = sorted[(int)(total * 0.80)];
   double p85    = sorted[(int)(total * 0.85)];
   double p90    = sorted[(int)(total * 0.90)];
   double p95    = sorted[(int)(total * 0.95)];

   // Desviación estándar
   double sqSum = 0;
   for(int i = 0; i < total; i++) sqSum += MathPow(ranges[i] - meanR, 2);
   double stdR = MathSqrt(sqSum / total);

   Print("\n=== ESTADÍSTICAS GLOBALES (" , total, " días) ===");
   Print("Media     : ", DoubleToString(meanR, 1), " pts ($", DoubleToString(meanR * _Point, 2), ")");
   Print("Mediana   : ", DoubleToString(medR, 1),  " pts ($", DoubleToString(medR  * _Point, 2), ")");
   Print("StdDev    : ", DoubleToString(stdR, 1),  " pts");
   Print("Mínimo    : ", DoubleToString(minR, 1),  " pts ($", DoubleToString(minR  * _Point, 2), ")");
   Print("Máximo    : ", DoubleToString(maxR, 1),  " pts ($", DoubleToString(maxR  * _Point, 2), ")");

   Print("\n=== PERCENTILES (PUNTOS) ===");
   Print("P10  : ", DoubleToString(p10, 1), " pts  ← demasiado pequeño para XAUUSD");
   Print("P15  : ", DoubleToString(p15, 1), " pts");
   Print("P20  : ", DoubleToString(p20, 1), " pts");
   Print("P25  : ", DoubleToString(p25, 1), " pts  ← MinSL usado en DJI30 (no recomendado para XAUUSD)");
   Print("P50  : ", DoubleToString(p50, 1), " pts  ← MinSL_Points RECOMENDADO para XAUUSD ★");
   Print("P60  : ", DoubleToString(p60, 1), " pts");
   Print("P70  : ", DoubleToString(p70, 1), " pts");
   Print("P75  : ", DoubleToString(p75, 1), " pts  ← MaxSL alternativo conservador");
   Print("P80  : ", DoubleToString(p80, 1), " pts");
   Print("P85  : ", DoubleToString(p85, 1), " pts");
   Print("P90  : ", DoubleToString(p90, 1), " pts  ← MaxSL_Points RECOMENDADO para XAUUSD ★");
   Print("P95  : ", DoubleToString(p95, 1), " pts");

   Print("\n=== CONFIGURACIÓN SUGERIDA PARA EA ===");
   Print("MinSL_Points = ", DoubleToString(p50, 0),  " (P50 — filtra rangos pequeños)");
   Print("MaxSL_Points = ", DoubleToString(p90, 0),  " (P90 — filtra días de altísima volatilidad)");
   Print("→ Días operables estimados: ~",
         DoubleToString((p90 - p50) / (p90 - p10) * 100.0, 0), "% del total = ",
         DoubleToString(total * (p90 - p50) / (p90 - p10) / 5.0, 0), " días/año aprox.");

   // Impacto del spread en el RR
   Print("\n=== IMPACTO DEL SPREAD EN RR EFECTIVO ===");
   Print("Spread estimado: ", SpreadEstPts, " pts = $", DoubleToString(SpreadEstPts * _Point, 2));
   double rngMed  = p50;
   double rrIdeal = 3.0;  // TP3
   double rr1Real = (rngMed * rrIdeal - SpreadEstPts) / (rngMed + SpreadEstPts);
   double rr2Real = (rngMed * 1.0 - SpreadEstPts) / (rngMed + SpreadEstPts);
   Print("Con SL=P50 (", DoubleToString(p50, 0), " pts):");
   Print("  RR ideal TP3 = 3.0 | RR efectivo = ", DoubleToString(rr1Real, 2),
         " (spread consume ", DoubleToString(SpreadEstPts / (rngMed * rrIdeal) * 100, 1), "% del TP3)");
   Print("  RR ideal TP1 = 1.0 | RR efectivo = ", DoubleToString(rr2Real, 2),
         " (spread consume ", DoubleToString(SpreadEstPts / rngMed * 100, 1), "% del TP1)");
   Print("⚠ Con spread > 40 pts, TP1 en rangos pequeños es negativo — ajustar MinSL_Points al alza");

   // Análisis por día de semana
   string dayNames[] = {"Domingo","Lunes","Martes","Miércoles","Jueves","Viernes","Sábado"};
   Print("\n=== ANÁLISIS POR DÍA DE SEMANA ===");
   Print(StringFormat("%-12s %6s %6s %6s %6s %6s %6s",
         "Día", "N", "Media", "Mediana", "P25", "P75", "P95"));
   Print("-------------------------------------------------------------");

   for(int d = 1; d <= 5; d++)  // Lun a Vie
   {
      int n = ArraySize(rangesByDay[d]);
      if(n < 3) { Print(dayNames[d], " : menos de 3 datos"); continue; }

      double dSorted[];
      ArrayCopy(dSorted, rangesByDay[d]);
      ArraySort(dSorted);

      double dSum = 0;
      for(int i = 0; i < n; i++) dSum += dSorted[i];
      double dMean = dSum / n;
      double dMed  = dSorted[(int)(n * 0.50)];
      double dP25  = dSorted[(int)(n * 0.25)];
      double dP75  = dSorted[(int)(n * 0.75)];
      double dP95  = dSorted[(int)(n * 0.95)];

      string flag = "";
      if(dMean < meanR * 0.85) flag = " ← rango pequeño (filtrar?)";
      if(dMean > meanR * 1.25) flag = " ← rango grande (volatilidad alta)";

      Print(StringFormat("%-12s %6d %6.1f %7.1f %6.1f %6.1f %6.1f%s",
            dayNames[d], n, dMean, dMed, dP25, dP75, dP95, flag));
   }

   // Top 10 mayores rangos (días de alta volatilidad)
   Print("\n=== TOP 10 DÍAS MÁS VOLÁTILES (rango más grande) ===");
   double topVals[10]; string topDates[10]; int topDays[10];
   for(int k = 0; k < 10; k++) { topVals[k] = 0; topDates[k] = ""; topDays[k] = 0; }
   for(int i = 0; i < total; i++)
   {
      if(ranges[i] > topVals[9])
      {
         topVals[9]  = ranges[i];
         topDates[9] = dates[i];
         topDays[9]  = weekdays[i];
         // Burbuja simple
         for(int j = 9; j > 0; j--)
         {
            if(topVals[j] > topVals[j-1])
            {
               double tv = topVals[j];  topVals[j] = topVals[j-1];  topVals[j-1] = tv;
               string ts = topDates[j]; topDates[j]= topDates[j-1]; topDates[j-1]= ts;
               int    ti = topDays[j];  topDays[j] = topDays[j-1];  topDays[j-1] = ti;
            }
         }
      }
   }
   for(int k = 0; k < 10; k++)
      if(topVals[k] > 0)
         Print(StringFormat("  %2d. %s (%s): %.1f pts",
               k+1, topDates[k], dayNames[topDays[k]], topVals[k]));

   // Top 10 menores rangos
   Print("\n=== TOP 10 DÍAS MENOS VOLÁTILES (rango más pequeño) ===");
   for(int k = 0; k < 10; k++)
   {
      int minIdx = 0;
      double minVal = 999999;
      for(int i = 0; i < total; i++)
      {
         if(ranges[i] < minVal && ranges[i] > 0)
         {
            // Asegurarse de que no lo hayamos listado ya
            bool alreadyListed = false;
            for(int j = 0; j < k; j++)
               if(dates[i] == topDates[j]) { alreadyListed = true; break; }
            if(!alreadyListed) { minVal = ranges[i]; minIdx = i; }
         }
      }
      if(minVal < 999999)
      {
         topDates[k] = dates[minIdx];
         Print(StringFormat("  %2d. %s (%s): %.1f pts",
               k+1, dates[minIdx], dayNames[weekdays[minIdx]], minVal));
      }
   }

   // Resumen ejecutivo para copiar-pegar en EA
   Print("\n=======================================================");
   Print("=== RESUMEN EJECUTIVO — COPIAR EN EA ===");
   Print("=======================================================");
   Print("// Calibrador XAUUSD — ", TimeToString(EndDate, TIME_DATE));
   Print("// Días analizados: ", total);
   Print("input double MinSL_Points = ", DoubleToString(p50, 0),
         ";  // P50 histórico XAUUSD");
   Print("input double MaxSL_Points = ", DoubleToString(p90, 0),
         ";  // P90 histórico XAUUSD");
   Print("// ATR_MaxMultiplier = 1.5 (mantener más conservador que DJI30)");
   Print("// Revisar FilterMonday y FilterFriday con el análisis por día");
   Print("=======================================================");
}
