{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                      BreakoutNY_RiskDiagnostic_XAUUSD.mq5       |
//|            Script de diagnóstico VPP y riesgo para XAUUSD        |
//|                                                                   |
//|  PROPÓSITO: Verificar el ValuePerPoint ANTES del primer backtest |
//|             El bloque OrderCalcProfit es la VERDAD ABSOLUTA      |
//|                                                                   |
//|  EJECUTAR: en gráfico XAUUSD (cualquier TF, es un script)       |
//|                                                                   |
//|  QUÉ VERIFICAR:                                                  |
//|  1. VPP calculado: AMBOS métodos deben dar ~$1.00/pt/lot         |
//|     Método 1: tv/ts = 0.01/0.01 = $1.00                         |
//|     Método 2: CS×Pt = 100×0.01 = $1.00 ← fallback              |
//|  2. OrderCalcProfit 100pts = ~$100 por lot → VPP=$1.00 ✓        |
//|  3. Lotaje de ejemplos: check de valores razonables              |
//|  4. Comparación vs DJI30 para entender la escala                |
//+------------------------------------------------------------------+
#property script_show_inputs
#property strict

input double RiskUSD    = 50.0;  // Riesgo para los ejemplos
input double TP1_RR     = 1.0;
input double TP2_RR     = 2.0;
input double TP3_RR     = 3.0;
input double SpreadPts  = 30.0;  // Spread estimado en puntos (para RR efectivo)

void OnStart()
{
   Print("===========================================================");
   Print("=== BreakoutNY RISK DIAGNOSTIC — XAUUSD FundingPips ===");
   Print("===========================================================");

   string sym = _Symbol;

   double tv  = SymbolInfoDouble(sym, SYMBOL_TRADE_TICK_VALUE);
   double ts  = SymbolInfoDouble(sym, SYMBOL_TRADE_TICK_SIZE);
   double cs  = SymbolInfoDouble(sym, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt  = SymbolInfoDouble(sym, SYMBOL_POINT);
   double mn  = SymbolInfoDouble(sym, SYMBOL_VOLUME_MIN);
   double mx  = SymbolInfoDouble(sym, SYMBOL_VOLUME_MAX);
   double ls  = SymbolInfoDouble(sym, SYMBOL_VOLUME_STEP);
   double bid = SymbolInfoDouble(sym, SYMBOL_BID);
   double ask = SymbolInfoDouble(sym, SYMBOL_ASK);
   int    dg  = (int)SymbolInfoInteger(sym, SYMBOL_DIGITS);
   int    sp  = (int)SymbolInfoInteger(sym, SYMBOL_SPREAD);

   Print("\n[1] ESPECIFICACIONES DEL CONTRATO");
   Print("  Símbolo        : ", sym);
   Print("  Dígitos        : ", dg, "  (esperado: 2 para XAUUSD)");
   Print("  ContractSize   : ", cs, "  (esperado: 100 oz)");
   Print("  TickSize       : ", ts, "  (esperado: 0.01)");
   Print("  TickValue      : ", tv, "  (esperado: 0.01)");
   Print("  Point (_Point) : ", pt, "  (esperado: 0.01)");
   Print("  Spread actual  : ", sp, " puntos  (típico NY: 20-50 pts)");
   Print("  Spread ($)     : $", DoubleToString(sp * pt, 2), " por lot");
   Print("  Bid/Ask        : ", DoubleToString(bid, dg), " / ", DoubleToString(ask, dg));
   Print("  VolumeMin      : ", mn, "  (lote mínimo)");
   Print("  VolumeMax      : ", mx, "  (FundingPips: 5 lotes máx para XAUUSD)");
   Print("  VolumeStep     : ", ls, "  (paso de lote)");

   // Verificaciones de specs
   if(MathAbs(cs - 100.0) > 0.1)
      Print("  ⚠ ContractSize ≠ 100 — verificar manualmente");
   else
      Print("  ✓ ContractSize = 100 oz — OK");

   if(MathAbs(pt - 0.01) > 0.0001)
      Print("  ⚠ Point ≠ 0.01 — verificar");
   else
      Print("  ✓ Point = 0.01 — OK");

   Print("\n[2] CÁLCULO VPP (ValuePerPoint)");

   double vpp1 = 0, vpp2 = 0;

   // Método 1: tv/ts
   if(tv > 0 && ts > 0)
   {
      vpp1 = tv / ts;
      Print("  Método 1 (tv/ts)  : ", tv, " / ", ts, " = $",
            DoubleToString(vpp1, 6), "/pt/lot");
   }
   else
      Print("  Método 1 (tv/ts)  : NO DISPONIBLE (tv=0 o ts=0)");

   // Método 2: CS×Point
   if(cs > 0 && pt > 0)
   {
      vpp2 = cs * pt;
      Print("  Método 2 (CS×Pt)  : ", cs, " × ", pt, " = $",
            DoubleToString(vpp2, 6), "/pt/lot (FALLBACK)");
   }

   double vppUsed = (vpp1 > 0) ? vpp1 : vpp2;

   Print("  VPP a usar        : $", DoubleToString(vppUsed, 6), "/pt/lot");

   if(MathAbs(vppUsed - 1.0) < 0.01)
      Print("  ✓ VPP = $1.00/pt/lot — CONFIRMADO para XAUUSD FundingPips");
   else if(vppUsed > 0)
      Print("  ⚠ VPP = $", DoubleToString(vppUsed, 4), " — DIFERENTE AL ESPERADO ($1.00) — INVESTIGAR");
   else
      Print("  ✗ ERROR: VPP = 0 — NO OPERAR HASTA CORREGIR");

   if(vpp1 > 0 && vpp2 > 0)
   {
      if(MathAbs(vpp1 - vpp2) < 0.001)
         Print("  ✓ Ambos métodos coinciden: $", DoubleToString(vpp1, 4));
      else
         Print("  ⚠ Divergencia entre métodos: M1=$", DoubleToString(vpp1, 4),
               " M2=$", DoubleToString(vpp2, 4), " — usar M1");
   }

   // Comparación con DJI30
   Print("\n[2b] COMPARACIÓN vs DJI30");
   Print("  DJI30: ContractSize=5, Point=0.01, VPP=$0.05/pt/lot");
   Print("  XAUUSD: ContractSize=100, Point=0.01, VPP=$", DoubleToString(vppUsed, 2), "/pt/lot");
   if(vppUsed > 0)
      Print("  → XAUUSD tiene VPP ", DoubleToString(vppUsed / 0.05, 0),
            "× mayor que DJI30 — un punto mueve ", DoubleToString(vppUsed / 0.05, 0),
            "× más dinero por lot");

   Print("\n[3] VERIFICACIÓN CON OrderCalcProfit (VERDAD ABSOLUTA)");
   Print("  Test: BUY 1.0 lot — SL a 100 puntos del precio actual");

   double priceFrom = ask - 100.0 * pt;  // SL a 100 pts debajo del ask
   double priceTo   = ask;               // entry (ask)
   double profit100 = 0;
   bool   ok100     = OrderCalcProfit(ORDER_TYPE_BUY, sym, 1.0, priceFrom, priceTo, profit100);

   if(ok100)
   {
      Print("  OrderCalcProfit(BUY, 1.0, SL@100pts) = $",
            DoubleToString(profit100, 2));
      if(MathAbs(profit100 - 100.0) < 2.0)
         Print("  ✓ CONFIRMADO: VPP = $1.00/pt/lot (profit≈$100 para 100pts)");
      else if(MathAbs(profit100 - 10.0) < 0.5)
         Print("  ✗ VPP real = $0.10/pt/lot (profit=$10) — DISCREPANCIA, revisar");
      else if(MathAbs(profit100 - 1.0) < 0.05)
         Print("  ✗ VPP real = $0.01/pt/lot (profit=$1) — DISCREPANCIA, revisar");
      else
         Print("  ⚠ profit=$", DoubleToString(profit100, 2),
               " — VPP real estimado = $", DoubleToString(profit100 / 100.0, 4), "/pt/lot");
   }
   else
      Print("  ✗ OrderCalcProfit FALLÓ (error=", GetLastError(),
            ") — verificar manualmente");

   // Test adicional con 300 pts (TP3)
   double profitTP3 = 0;
   bool   okTP3 = OrderCalcProfit(ORDER_TYPE_BUY, sym, 1.0, ask,
                                  ask + 300.0 * pt, profitTP3);
   if(okTP3)
      Print("  Test TP3 (300pts BUY 1.0 lot): $", DoubleToString(profitTP3, 2),
            " (esperado ~$300)");

   // Test SELL
   double profitSell = 0;
   bool   okSell = OrderCalcProfit(ORDER_TYPE_SELL, sym, 1.0, bid,
                                   bid - 100.0 * pt, profitSell);
   if(okSell)
      Print("  Test SELL 100pts (1.0 lot): $", DoubleToString(profitSell, 2),
            " (esperado ~$100)");

   Print("\n[4] TABLA DE LOTAJE (Risk=$", RiskUSD, ")");
   Print(StringFormat("  %-8s %-10s %-8s %-10s %-10s %-10s %-8s",
         "SL(pts)", "SL($)", "Lots", "Risk$", "TP1($)", "TP3($)", "RR_real"));
   Print("  " + StringRepeat("-", 70));

   double slTests[] = {50.0, 80.0, 100.0, 120.0, 150.0, 200.0, 250.0, 300.0, 400.0, 500.0};

   for(int i = 0; i < ArraySize(slTests); i++)
   {
      double slPts  = slTests[i];
      double slDist = slPts * pt;
      double lRaw   = (vppUsed > 0) ? RiskUSD / (slPts * vppUsed) : 0;
      double lNorm  = MathMax(mn, MathMin(MathMin(mx, 5.0), MathFloor(lRaw / ls) * ls));
      double rReal  = slPts * vppUsed * lNorm;
      double tp1Val = slPts * TP1_RR * vppUsed * lNorm;
      double tp3Val = slPts * TP3_RR * vppUsed * lNorm;
      // RR efectivo considerando spread
      double rrEff  = (slPts > SpreadPts) ? (slPts * TP3_RR - SpreadPts) / (slPts + SpreadPts) : 0;

      string flag = "";
      if(lRaw > 5.0) flag = " ← LOTE CAPADO a 5.0 (FundingPips limit)";
      if(slPts < 80)  flag = " ← rango pequeño — evitar con MinSL";

      Print(StringFormat("  %-8.0f %-10.2f %-8.2f %-10.2f %-10.2f %-10.2f %-8.2f%s",
            slPts, slDist, lNorm, rReal, tp1Val, tp3Val, rrEff, flag));
   }

   Print("\n[5] ANÁLISIS DE SPREAD vs RR");
   Print("  Spread estimado NY: ", SpreadPts, " pts = $",
         DoubleToString(SpreadPts * pt, 2), " | Costo por lot = $",
         DoubleToString(SpreadPts * vppUsed, 2));
   Print("  Con SL de 100 pts:");
   Print("    Costo spread/SL = ", DoubleToString(SpreadPts / 100.0 * 100.0, 1),
         "% del SL → RR efectivo TP3 =",
         DoubleToString((100.0 * TP3_RR - SpreadPts) / (100.0 + SpreadPts), 2));
   Print("  Con SL de 200 pts:");
   Print("    Costo spread/SL = ", DoubleToString(SpreadPts / 200.0 * 100.0, 1),
         "% del SL → RR efectivo TP3 =",
         DoubleToString((200.0 * TP3_RR - SpreadPts) / (200.0 + SpreadPts), 2));
   Print("  ⚠ MinSL_Points debe ser suficientemente grande para que el",
         " spread no destruya el RR efectivo");
   Print("  ⚠ Regla práctica: MinSL_Points > 3 × Spread (", DoubleToString(SpreadPts * 3, 0),
         " pts mínimo recomendado)");

   Print("\n[6] LÍMITE ESPECÍFICO FUNDINGPIPS XAUUSD");
   Print("  VolumeMax declarado : ", mx, " lotes");
   Print("  VolumeMax efectivo  : ", MathMin(mx, 5.0), " lotes (FundingPips limit)");
   Print("  Max riesgo en 1 trade: $",
         DoubleToString(100.0 * MathMin(mx, 5.0) * vppUsed * RiskUSD / RiskUSD, 0),
         " equivalente con lotaje máximo");
   Print("  ⚠ Con VolumeMax=5: riesgo máximo absoluto en XAUUSD = ",
         DoubleToString(5.0 * 100.0 * pt * vppUsed, 0), " × 100pts = $",
         DoubleToString(5.0 * 100.0 * vppUsed, 0));

   Print("\n[7] COMPARACIÓN DJI30 vs XAUUSD — RESUMEN");
   Print("  ┌─────────────────┬──────────────┬────────────────┐");
   Print("  │ Parámetro       │    DJI30     │   XAUUSD       │");
   Print("  ├─────────────────┼──────────────┼────────────────┤");
   Print("  │ ContractSize    │     5.0      │    100.0       │");
   Print("  │ Point           │     0.01     │      0.01      │");
   Print("  │ VPP             │    $0.05     │     $1.00      │");
   Print("  │ SL típico (pts) │   8200-20k   │  P50-P90 est.  │");
   Print("  │ Lots (Risk$50)  │  0.5-1.2 L   │   0.15-0.50 L  │");
   Print("  │ ATR MaxMult     │     2.0      │      1.5       │");
   Print("  │ Vol.Max(FP)     │    10.0      │      5.0       │");
   Print("  └─────────────────┴──────────────┴────────────────┘");

   Print("\n===========================================================");
   Print("DIAGNÓSTICO COMPLETADO — Revisar resultados arriba");
   Print("SIGUIENTE PASO: Correr BreakoutNY_Calibrator_XAUUSD.mq5");
   Print("               para obtener P50 y P90 del rango histórico");
   Print("===========================================================");
}

