  return new Paragraph({ heading: HeadingLevel.HEADING_3, children: [new TextRun({ text, bold: true, font: "Arial", size: 24 })] });
}
function p(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 100 },
    children: [new TextRun({ text, font: "Arial", size: 22, ...opts })]
  });
}
function bold(text) { return new TextRun({ text, bold: true, font: "Arial", size: 22 }); }
function run(text)  { return new TextRun({ text, font: "Arial", size: 22 }); }
function code(text) { return new TextRun({ text, font: "Courier New", size: 20 }); }
function warn(text) { return new Paragraph({ spacing: { after: 120 }, children: [new TextRun({ text: "⚠ " + text, bold: true, color: "C0392B", font: "Arial", size: 22 })] }); }
function ok(text)   { return new Paragraph({ spacing: { after: 80  }, children: [new TextRun({ text: "✓ " + text, color: "1A7A3C", font: "Arial", size: 22 })] }); }
function bullet(text) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { after: 80 },
    children: [new TextRun({ text, font: "Arial", size: 22 })]
  });
}
function spacer() { return new Paragraph({ children: [new TextRun("")] }); }

function cell(text, opts = {}) {
