                    left:{style:BorderStyle.NONE}, right:{style:BorderStyle.NONE} };

function h1(text) {
  return new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun({ text, bold: true, font: "Arial", size: 32 })] });
