input int    SessionCloseMin      = 0;

//--- Inputs: Riesgo
input double RiskAmountUSD        = 50.0; // Riesgo en USD por trade (1% de $5k challenge)

//--- Inputs: Trade Management
input double BE_BufferPct         = 50.0; // BE activa al 50% del SL (NO usar < 30)
input double TP1_RR               = 1.0;  // TP1 — informacional (SL ya en entry con BE)
input double TP2_RR               = 2.0;  // TP2 — SL sube a TP1 tras alcanzar este nivel
input double TP3_RR               = 3.0;  // Target final
input bool   EnablePartials       = false; // Sin parciales — validado en DJI30

//--- Inputs: Filtros de rango
// ⚠ CALIBRAR con BreakoutNY_Calibrator_SP500.mq5 antes de optimizar
// Valores iniciales estimados: SP500 mueve ~40% menos puntos que DJI30
// DJI30: MinSL=8200, MaxSL=20000 → SP500 estimado: MinSL=3000, MaxSL=8000
// OBLIGATORIO verificar con calibrador sobre historial 2021-2024
input int    MinSL_Points         = 3000; // P25 del rango histórico SP500 — CALIBRAR
input int    MaxSL_Points         = 8000; // P75-P90 del rango histórico SP500 — CALIBRAR

//--- Inputs: Filtro ATR
input bool   ATR_FilterEnable     = true;
input int    ATR_Period           = 14;
input double ATR_MaxMultiplier    = 2.0;  // Bloquea días con ATR > 2× baseline
input double ATR_MinMultiplier    = 0.3;  // Bloquea días con ATR < 0.3× baseline
input int    ATR_BaselineDays     = 20;   // Ventana rolling baseline

//--- Inputs: Filtros de día
// ⚠ FilterWednesday: NO filtrar hasta medir SP500 independientemente
// DJI30 tiene miércoles negativo, SP500 puede ser diferente — medir primero
input bool   FilterMonday         = true;
input bool   FilterTuesday        = true;
input bool   FilterWednesday      = true;  // MEDIR PRIMERO — luego decidir
input bool   FilterThursday       = true;
input bool   FilterFriday         = true;

//--- Inputs: Confirmación
input bool   ConfirmOnClose       = true;  // NUNCA OPTIMIZAR — siempre true

//--- Inputs: Identificación
input int    MagicNumber          = 202403; // SP500 — diferente a DJI30 (202402)

//--- Inputs: Diagnóstico
input bool   EnableDiagLog        = true;  // Log detallado — desactivar en producción

//+------------------------------------------------------------------+
//| Variables globales                                               |
//+------------------------------------------------------------------+

// Estado del rango
double g_rangeHigh      = 0.0;
double g_rangeLow       = 0.0;
double g_slDistance     = 0.0;
bool   g_rangeCalculated = false;

// Estado del breakout
bool   g_breakoutPending = false;
int    g_breakoutDir     = 0;   // +1 BUY, -1 SELL
datetime g_breakoutTime  = 0;
double g_breakoutBarClose = 0.0;

// Estado del trade
bool   g_tradeOpenToday  = false;
bool   g_tradeDoneToday  = false;
ulong  g_ticket          = 0;

// BE / TP tracking
bool   g_beActivated     = false;
bool   g_tp2Activated    = false;
double g_entryPrice      = 0.0;
double g_lotSize         = 0.0;

// Día actual
datetime g_lastBarTime   = 0;
int      g_todayDOW      = 0;  // 0=Sun, 1=Mon..5=Fri, 6=Sat

// VPP — calculado una vez en OnInit
double g_vpp             = 0.0;

// ATR handle
int    g_atrHandle       = INVALID_HANDLE;

// CSV Logger
int    g_csvHandle       = INVALID_HANDLE;
string g_csvFileName     = "";

//+------------------------------------------------------------------+
//| Expert initialization                                            |
//+------------------------------------------------------------------+
int OnInit()
{
   Print("=== BreakoutNY SP500 v1.0 — OnInit ===");
   Print("Symbol: ", Symbol(), " | Magic: ", MagicNumber);

   //--- 1. Diagnóstico VPP — CRÍTICO
   DiagnoseVPP();

   //--- 2. Calcular VPP usando Formula B (ContractSize × Point)
   //    ⚠ NO usar TickValue/TickSize — pueden ser 0 en FP (bug del broker)
   double cs = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_CONTRACT_SIZE);
   double pt = SymbolInfoDouble(Symbol(), SYMBOL_POINT);
   g_vpp = cs * pt;

   if(g_vpp <= 0)
   {
      Print("❌ ERROR CRÍTICO: VPP = 0 o negativo. Verificar símbolo y contrato.");
      return INIT_FAILED;
   }
   Print("✓ VPP calculado: $", DoubleToString(g_vpp, 6), " por Point por lote");
   Print("  (ContractSize=", cs, " × Point=", pt, ")");

   //--- 3. Verificar VPP con OrderCalcProfit — la verdad absoluta
   double testProfit = 0.0;
   double ask = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   bool ok = OrderCalcProfit(ORDER_TYPE_BUY, Symbol(), 1.0,
                             ask, ask + 100 * pt, testProfit);
   if(ok)
   {
      double impliedVPP = testProfit / 100.0;
      Print("✓ VPP verificado con OrderCalcProfit: $", DoubleToString(impliedVPP, 6),
            " por Point (100pt × 1lot = $", DoubleToString(testProfit, 2), ")");
      double ratio = (impliedVPP > 0) ? g_vpp / impliedVPP : 0;
      if(MathAbs(ratio - 1.0) > 0.01)
         Print("⚠ DISCREPANCIA VPP: Formula B = $", DoubleToString(g_vpp,6),
               " | OrderCalcProfit = $", DoubleToString(impliedVPP,6),
               " — Usar OrderCalcProfit como verdad");
      else
         Print("✓ VPP consistente — Formula B confirmada");
      // Usar VPP de OrderCalcProfit como verdad
      if(ok && testProfit > 0) g_vpp = impliedVPP;
   }
   else
      Print("⚠ OrderCalcProfit falló — usando Formula B: $", DoubleToString(g_vpp,6));

   //--- 4. Inicializar ATR
   g_atrHandle = iATR(Symbol(), PERIOD_M5, ATR_Period);
   if(g_atrHandle == INVALID_HANDLE)
   {
      Print("❌ ERROR: No se pudo crear handle ATR");
      return INIT_FAILED;
   }

   //--- 5. Inicializar CSV Logger
   InitCSVLog();

   //--- 6. Resumen de configuración
   Print("--- Configuración ---");
   Print("ServerOffset: UTC+", ServerOffsetHours);
   Print("Rango: ", RangeBar1_Hour, ":", (RangeBar1_Min<10?"0":""), RangeBar1_Min,
         " — ", RangeBar1_Hour, ":", (RangeBar1_Min+10<10?"0":""), RangeBar1_Min+10, " UTC");
   Print("Entrada: 14:50 — 14:", (50+EntryWindowEnd_Min<10?"0":""), 50+EntryWindowEnd_Min-50, " UTC");
   Print("SessionClose: ", SessionCloseHour, ":00 UTC");
   Print("MinSL=", MinSL_Points, " pts | MaxSL=", MaxSL_Points, " pts");
   Print("Risk=$", RiskAmountUSD, " | BE=", BE_BufferPct, "% | TP3=", TP3_RR, "R");
   Print("ATR Filter: ", (ATR_FilterEnable?"ON":"OFF"),
         " [", ATR_MinMultiplier, "× — ", ATR_MaxMultiplier, "×]");
   string dayFilter = "";
   if(!FilterMonday) dayFilter += "Lun-OFF ";
   if(!FilterTuesday) dayFilter += "Mar-OFF ";
   if(!FilterWednesday) dayFilter += "Mie-OFF ";
   if(!FilterThursday) dayFilter += "Jue-OFF ";
   if(!FilterFriday) dayFilter += "Vie-OFF ";
   if(dayFilter == "") dayFilter = "Todos ON";
   Print("Días activos: ", dayFilter);
   Print("=====================================");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Diagnóstico completo del contrato SP500                          |
//+------------------------------------------------------------------+
void DiagnoseVPP()
{
   Print("--- [DIAGNÓSTICO VPP SP500] ---");
   double cs  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_CONTRACT_SIZE);
   double tv  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_TICK_VALUE);
   double ts  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_TICK_SIZE);
   double pt  = SymbolInfoDouble(Symbol(), SYMBOL_POINT);
   double bid = SymbolInfoDouble(Symbol(), SYMBOL_BID);
   int    dig = (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS);
   double volMin = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MIN);
   double volMax = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
   double volStp = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_STEP);

   Print("[1] ContractSize  = ", cs);
   Print("[2] TickSize      = ", ts,  (ts == 0 ? " ← REPORTA 0 (bug broker)" : " ← OK"));
   Print("[3] TickValue     = ", tv,  (tv == 0 ? " ← REPORTA 0 (bug broker)" : " ← OK"));
   Print("[4] _Point        = ", pt);
   Print("[5] Digits        = ", dig);
   Print("[6] Current BID   = ", bid);
   Print("[7] VolumeMin     = ", volMin, " | Max=", volMax, " | Step=", volStp);

   // Formula A (puede fallar si TV o TS = 0)
   double vppA = (ts > 0) ? tv / ts : 0.0;
   // Formula B (siempre disponible)
   double vppB = cs * pt;

   Print("[VPP-A] TickValue/TickSize = ", (ts > 0 ? DoubleToString(vppA,6) : "N/A (TS=0 → NO USAR)"));
   Print("[VPP-B] ContractSize×Point = ", DoubleToString(vppB,6), " ← USAR ESTA");

   // Verificación OrderCalcProfit
   double ask = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   double profit100 = 0.0;
   bool ok = OrderCalcProfit(ORDER_TYPE_BUY, Symbol(), 1.0,
                             ask, ask + 100.0 * pt, profit100);
   if(ok)
      Print("[VPP-C] OrderCalcProfit 100pt×1lot = $", DoubleToString(profit100,2),
            " → VPP = $", DoubleToString(profit100/100.0, 6), " ← VERDAD ABSOLUTA");
   else
      Print("[VPP-C] OrderCalcProfit FALLÓ — modo backtest o símbolo no disponible");

   // Estimación lotes para $50 de riesgo con SL de 5000 puntos
   double slTest = 5000.0;
   double lotsTest = (vppB > 0) ? RiskAmountUSD / (slTest * vppB) : 0;
   lotsTest = NormalizeDouble(MathRound(lotsTest / volStp) * volStp, 2);
   Print("[EJEMPLO] Riesgo=$", RiskAmountUSD, " SL=", slTest,
         "pts → Lotes estimados=", lotsTest, " (con VPP-B=$", DoubleToString(vppB,6), ")");
   Print("--- [FIN DIAGNÓSTICO] ---");
}

