// OBLIGATORIO verificar con calibrador sobre historial 2021-2024
input int    MinSL_Points         = 3000; // P25 del rango histórico SP500 — CALIBRAR
input int    MaxSL_Points         = 8000; // P75-P90 del rango histórico SP500 — CALIBRAR

