//--- Inputs: Identificación
input int    MagicNumber          = 202403; // SP500 — diferente a DJI30 (202402)

//--- Inputs: Diagnóstico
input bool   EnableDiagLog        = true;  // Log detallado — desactivar en producción

//+------------------------------------------------------------------+
//| Variables globales                                               |
//+------------------------------------------------------------------+

// Estado del rango
double g_rangeHigh      = 0.0;
double g_rangeLow       = 0.0;
double g_slDistance     = 0.0;
bool   g_rangeCalculated = false;

// Estado del breakout
bool   g_breakoutPending = false;
int    g_breakoutDir     = 0;   // +1 BUY, -1 SELL
datetime g_breakoutTime  = 0;
double g_breakoutBarClose = 0.0;

// Estado del trade
bool   g_tradeOpenToday  = false;
bool   g_tradeDoneToday  = false;
ulong  g_ticket          = 0;

// BE / TP tracking
bool   g_beActivated     = false;
bool   g_tp2Activated    = false;
double g_entryPrice      = 0.0;
double g_lotSize         = 0.0;

// Día actual
datetime g_lastBarTime   = 0;
int      g_todayDOW      = 0;  // 0=Sun, 1=Mon..5=Fri, 6=Sat

// VPP — calculado una vez en OnInit
double g_vpp             = 0.0;

// ATR handle
