      if(MathAbs(ratio - 1.0) > 0.01)
         Print("⚠ DISCREPANCIA VPP: Formula B = $", DoubleToString(g_vpp,6),
               " | OrderCalcProfit = $", DoubleToString(impliedVPP,6),
               " — Usar OrderCalcProfit como verdad");
      else
         Print("✓ VPP consistente — Formula B confirmada");
      // Usar VPP de OrderCalcProfit como verdad
      if(ok && testProfit > 0) g_vpp = impliedVPP;
   }
   else
      Print("⚠ OrderCalcProfit falló — usando Formula B: $", DoubleToString(g_vpp,6));

   //--- 4. Inicializar ATR
   g_atrHandle = iATR(Symbol(), PERIOD_M5, ATR_Period);
   if(g_atrHandle == INVALID_HANDLE)
   {
      Print("❌ ERROR: No se pudo crear handle ATR");
      return INIT_FAILED;
   }

   //--- 5. Inicializar CSV Logger
   InitCSVLog();

   //--- 6. Resumen de configuración
   Print("--- Configuración ---");
   Print("ServerOffset: UTC+", ServerOffsetHours);
   Print("Rango: ", RangeBar1_Hour, ":", (RangeBar1_Min<10?"0":""), RangeBar1_Min,
         " — ", RangeBar1_Hour, ":", (RangeBar1_Min+10<10?"0":""), RangeBar1_Min+10, " UTC");
   Print("Entrada: 14:50 — 14:", (50+EntryWindowEnd_Min<10?"0":""), 50+EntryWindowEnd_Min-50, " UTC");
   Print("SessionClose: ", SessionCloseHour, ":00 UTC");
   Print("MinSL=", MinSL_Points, " pts | MaxSL=", MaxSL_Points, " pts");
   Print("Risk=$", RiskAmountUSD, " | BE=", BE_BufferPct, "% | TP3=", TP3_RR, "R");
   Print("ATR Filter: ", (ATR_FilterEnable?"ON":"OFF"),
         " [", ATR_MinMultiplier, "× — ", ATR_MaxMultiplier, "×]");
   string dayFilter = "";
   if(!FilterMonday) dayFilter += "Lun-OFF ";
   if(!FilterTuesday) dayFilter += "Mar-OFF ";
   if(!FilterWednesday) dayFilter += "Mie-OFF ";
   if(!FilterThursday) dayFilter += "Jue-OFF ";
   if(!FilterFriday) dayFilter += "Vie-OFF ";
   if(dayFilter == "") dayFilter = "Todos ON";
   Print("Días activos: ", dayFilter);
   Print("=====================================");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Diagnóstico completo del contrato SP500                          |
//+------------------------------------------------------------------+
void DiagnoseVPP()
{
   Print("--- [DIAGNÓSTICO VPP SP500] ---");
   double cs  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_CONTRACT_SIZE);
   double tv  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_TICK_VALUE);
   double ts  = SymbolInfoDouble(Symbol(), SYMBOL_TRADE_TICK_SIZE);
   double pt  = SymbolInfoDouble(Symbol(), SYMBOL_POINT);
   double bid = SymbolInfoDouble(Symbol(), SYMBOL_BID);
   int    dig = (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS);
   double volMin = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MIN);
   double volMax = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
   double volStp = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_STEP);

   Print("[1] ContractSize  = ", cs);
   Print("[2] TickSize      = ", ts,  (ts == 0 ? " ← REPORTA 0 (bug broker)" : " ← OK"));
   Print("[3] TickValue     = ", tv,  (tv == 0 ? " ← REPORTA 0 (bug broker)" : " ← OK"));
   Print("[4] _Point        = ", pt);
   Print("[5] Digits        = ", dig);
   Print("[6] Current BID   = ", bid);
   Print("[7] VolumeMin     = ", volMin, " | Max=", volMax, " | Step=", volStp);

   // Formula A (puede fallar si TV o TS = 0)
   double vppA = (ts > 0) ? tv / ts : 0.0;
   // Formula B (siempre disponible)
   double vppB = cs * pt;

   Print("[VPP-A] TickValue/TickSize = ", (ts > 0 ? DoubleToString(vppA,6) : "N/A (TS=0 → NO USAR)"));
   Print("[VPP-B] ContractSize×Point = ", DoubleToString(vppB,6), " ← USAR ESTA");

   // Verificación OrderCalcProfit
   double ask = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   double profit100 = 0.0;
   bool ok = OrderCalcProfit(ORDER_TYPE_BUY, Symbol(), 1.0,
                             ask, ask + 100.0 * pt, profit100);
   if(ok)
      Print("[VPP-C] OrderCalcProfit 100pt×1lot = $", DoubleToString(profit100,2),
            " → VPP = $", DoubleToString(profit100/100.0, 6), " ← VERDAD ABSOLUTA");
   else
      Print("[VPP-C] OrderCalcProfit FALLÓ — modo backtest o símbolo no disponible");

   // Estimación lotes para $50 de riesgo con SL de 5000 puntos
   double slTest = 5000.0;
   double lotsTest = (vppB > 0) ? RiskAmountUSD / (slTest * vppB) : 0;
   lotsTest = NormalizeDouble(MathRound(lotsTest / volStp) * volStp, 2);
   Print("[EJEMPLO] Riesgo=$", RiskAmountUSD, " SL=", slTest,
         "pts → Lotes estimados=", lotsTest, " (con VPP-B=$", DoubleToString(vppB,6), ")");
   Print("--- [FIN DIAGNÓSTICO] ---");
}

//+------------------------------------------------------------------+
//| Expert deinitialization                                          |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(g_atrHandle != INVALID_HANDLE) IndicatorRelease(g_atrHandle);
   if(g_csvHandle != INVALID_HANDLE) FileClose(g_csvHandle);
   Print("BreakoutNY SP500 v1.0 — Deinit. Razón: ", reason);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Solo procesar en nueva barra M5
   datetime barTime = iTime(Symbol(), PERIOD_M5, 0);
   bool isNewBar = (barTime != g_lastBarTime);
   if(isNewBar) g_lastBarTime = barTime;

   // Hora del servidor
   datetime serverNow = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(serverNow, dt);

   // Convertir a UTC
   int serverHour = dt.hour;
   int serverMin  = dt.min;
   int utcHour    = (serverHour - ServerOffsetHours + 24) % 24;
   int utcMin     = serverMin;

   // Día de la semana (en UTC corregido)
   int dow = dt.day_of_week; // 0=Dom, 1=Lun..5=Vie, 6=Sab

   // Reset diario al inicio de la sesión pre-NY (14:30 UTC)
   if(isNewBar && utcHour == 14 && utcMin == 30)
      ResetDaily(dow);

   // --- Si ya hay trade abierto: gestionar ---
   if(g_tradeOpenToday && g_ticket > 0)
   {
      ManageTrade(utcHour, utcMin, serverNow);
      return;
   }

   // --- Si ya operamos hoy: nada más ---
   if(g_tradeDoneToday) return;

   // --- Calcular rango en 14:50 UTC (primera oportunidad tras 3 velas) ---
   if(isNewBar && utcHour == 14 && utcMin == 50 && !g_rangeCalculated)
   {
      CalculateRange();
      return;
   }

   // --- Ventana de entrada: 14:50 hasta EntryWindowEnd_Min ---
   // EntryWindowEnd_Min=15 → cierra a las 15:05 UTC
   bool inWindow = false;
   if(utcHour == 14 && utcMin >= 50) inWindow = true;
   if(utcHour == 15 && utcMin < EntryWindowEnd_Min) inWindow = true;

   if(!inWindow || !g_rangeCalculated) return;

   // --- Detectar breakout (Fase A) ---
   if(!g_breakoutPending && !g_tradeOpenToday)
      DetectBreakout();

   // --- Confirmar y entrar (Fase B) — solo en nueva barra ---
   if(g_breakoutPending && isNewBar && !g_tradeOpenToday)
      ConfirmAndEnter(utcHour, utcMin, dow);
}

//+------------------------------------------------------------------+
//| Reset diario                                                     |
//+------------------------------------------------------------------+
void ResetDaily(int dow)
{
   g_rangeCalculated  = false;
   g_rangeHigh        = 0.0;
   g_rangeLow         = 0.0;
   g_slDistance       = 0.0;
   g_breakoutPending  = false;
   g_breakoutDir      = 0;
   g_breakoutTime     = 0;
   g_tradeOpenToday   = false;
   g_tradeDoneToday   = false;
   g_ticket           = 0;
   g_beActivated      = false;
   g_tp2Activated     = false;
   g_entryPrice       = 0.0;
   g_lotSize          = 0.0;
   g_todayDOW         = dow;
   if(EnableDiagLog)
      Print("✦ Reset diario — DOW=", dow, " [", DayName(dow), "]");
}

//+------------------------------------------------------------------+
//| Calcular rango de las 3 velas pre-NY                             |
//+------------------------------------------------------------------+
void CalculateRange()
{
   // Las 3 velas cerradas son: índice 3 (14:35), 2 (14:40), 1 (14:45)
   // La vela 0 es la actual (14:50 — aún abierta)
   // ConfirmOnClose=true: esperar cierre de la vela 14:50 para entrar

   double h3 = iHigh(Symbol(), PERIOD_M5, 3);
   double h2 = iHigh(Symbol(), PERIOD_M5, 2);
   double h1 = iHigh(Symbol(), PERIOD_M5, 1);
   double l3 = iLow(Symbol(), PERIOD_M5, 3);
   double l2 = iLow(Symbol(), PERIOD_M5, 2);
   double l1 = iLow(Symbol(), PERIOD_M5, 1);

   if(h3 <= 0 || l3 <= 0)
   {
      Print("❌ Error: No hay datos de velas para calcular el rango");
      return;
   }

   g_rangeHigh = MathMax(h3, MathMax(h2, h1));
   g_rangeLow  = MathMin(l3, MathMin(l2, l1));
   g_slDistance = (g_rangeHigh - g_rangeLow) / SymbolInfoDouble(Symbol(), SYMBOL_POINT);

   // Filtrar por rango mínimo/máximo
   if(g_slDistance < MinSL_Points)
   {
      if(EnableDiagLog)
         Print("⊘ Rango demasiado PEQUEÑO: ", g_slDistance, " pts < MinSL=", MinSL_Points,
               " — Sin operación hoy");
      g_tradeDoneToday = true;
      return;
   }
   if(g_slDistance > MaxSL_Points)
   {
      if(EnableDiagLog)
         Print("⊘ Rango demasiado GRANDE: ", g_slDistance, " pts > MaxSL=", MaxSL_Points,
               " — Sin operación hoy");
      g_tradeDoneToday = true;
      return;
   }

   // Filtro ATR
   if(ATR_FilterEnable && !CheckATRFilter())
   {
      g_tradeDoneToday = true;
      return;
   }

   // Filtro de día de semana
   if(!CheckDayFilter())
   {
      g_tradeDoneToday = true;
      return;
   }

   g_rangeCalculated = true;

   if(EnableDiagLog)
      Print("✓ Rango calculado: High=", DoubleToString(g_rangeHigh,2),
            " Low=", DoubleToString(g_rangeLow,2),
            " SL=", DoubleToString(g_slDistance,1), " pts [",
            DayName(g_todayDOW), "]");
}

//+------------------------------------------------------------------+
//| Verificar filtro ATR                                             |
//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double atrBuffer[];
   ArraySetAsSeries(atrBuffer, true);
   int copied = CopyBuffer(g_atrHandle, 0, 1, ATR_BaselineDays + 5, atrBuffer);
   if(copied < ATR_BaselineDays + 1)
   {
      Print("⚠ ATR: datos insuficientes (", copied, ") — filtro omitido");
      return true;
   }

   double currentATR = atrBuffer[0];
   double sumATR = 0;
   for(int i = 1; i <= ATR_BaselineDays; i++) sumATR += atrBuffer[i];
   double baselineATR = sumATR / ATR_BaselineDays;

   if(baselineATR <= 0) { Print("⚠ ATR baseline=0 — filtro omitido"); return true; }

   double ratio = currentATR / baselineATR;

   if(ratio > ATR_MaxMultiplier)
   {
      if(EnableDiagLog)
         Print("⊘ ATR demasiado ALTO: ", DoubleToString(ratio,2), "× > ", ATR_MaxMultiplier, "× baseline — Sin operación");
      return false;
   }
   if(ratio < ATR_MinMultiplier)
   {
      if(EnableDiagLog)
         Print("⊘ ATR demasiado BAJO: ", DoubleToString(ratio,2), "× < ", ATR_MinMultiplier, "× baseline — Sin operación");
      return false;
   }

   if(EnableDiagLog)
      Print("✓ ATR OK: ", DoubleToString(ratio,2), "× baseline [ATR=",
            DoubleToString(currentATR,2), " | Base=", DoubleToString(baselineATR,2), "]");
   return true;
}

//+------------------------------------------------------------------+
//| Verificar filtro de día de semana                                |
//+------------------------------------------------------------------+
bool CheckDayFilter()
{
   bool allowed = false;
   switch(g_todayDOW)
   {
      case 1: allowed = FilterMonday;    break;
      case 2: allowed = FilterTuesday;   break;
      case 3: allowed = FilterWednesday; break;
      case 4: allowed = FilterThursday;  break;
      case 5: allowed = FilterFriday;    break;
      default: allowed = false; break; // Dom/Sab
   }
   if(!allowed && EnableDiagLog)
      Print("⊘ Día filtrado: ", DayName(g_todayDOW), " — Sin operación");
   return allowed;
}

//+------------------------------------------------------------------+
//| Detectar breakout (Fase A)                                       |
//+------------------------------------------------------------------+
void DetectBreakout()
{
   if(!g_rangeCalculated) return;

   double ask = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   double bid = SymbolInfoDouble(Symbol(), SYMBOL_BID);

   if(ask > g_rangeHigh)
   {
      g_breakoutPending  = true;
      g_breakoutDir      = 1;  // BUY
      g_breakoutTime     = TimeCurrent();
      if(EnableDiagLog)
         Print("→ Breakout ALCISTA detectado: ask=", DoubleToString(ask,2),
               " > rangeHigh=", DoubleToString(g_rangeHigh,2));
   }
   else if(bid < g_rangeLow)
   {
      g_breakoutPending  = true;
      g_breakoutDir      = -1; // SELL
      g_breakoutTime     = TimeCurrent();
      if(EnableDiagLog)
         Print("→ Breakout BAJISTA detectado: bid=", DoubleToString(bid,2),
               " < rangeLow=", DoubleToString(g_rangeLow,2));
   }
}

//+------------------------------------------------------------------+
//| Confirmar y entrar (Fase B — en nueva vela)                      |
//+------------------------------------------------------------------+
void ConfirmAndEnter(int utcHour, int utcMin, int dow)
{
   if(!g_breakoutPending) return;

   // Verificar que la ventana sigue abierta
   bool stillInWindow = (utcHour == 14 && utcMin >= 50) ||
                        (utcHour == 15 && utcMin < EntryWindowEnd_Min);
   if(!stillInWindow)
   {
      if(EnableDiagLog) Print("⊘ Ventana de entrada cerrada — breakout cancelado");
      g_breakoutPending = false;
      g_tradeDoneToday  = true;
      return;
   }

   double pt  = SymbolInfoDouble(Symbol(), SYMBOL_POINT);
   double ask = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   double bid = SymbolInfoDouble(Symbol(), SYMBOL_BID);

   // Confirmar que el precio sigue del lado correcto
   if(g_breakoutDir == 1 && ask <= g_rangeHigh)
   {
      if(EnableDiagLog) Print("⊘ Confirmación fallida: ask=", DoubleToString(ask,2),
                               " regresó bajo rangeHigh=", DoubleToString(g_rangeHigh,2));
      g_breakoutPending = false;
      // No marcar tradeDoneToday — puede haber otro breakout
      return;
   }
   if(g_breakoutDir == -1 && bid >= g_rangeLow)
   {
      if(EnableDiagLog) Print("⊘ Confirmación fallida: bid=", DoubleToString(bid,2),
                               " regresó sobre rangeLow=", DoubleToString(g_rangeLow,2));
      g_breakoutPending = false;
      return;
   }

   // --- Calcular lotaje con VPP correcto ---
   double slPts  = g_slDistance; // en puntos
   double slDist = slPts * pt;   // en precio

   if(g_vpp <= 0 || slPts <= 0)
   {
      Print("❌ VPP o SL inválido — no se puede entrar");
      g_tradeDoneToday = true;
      return;
   }

   double volMin = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MIN);
   double volMax = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
   double volStp = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_STEP);

   double lotsRaw = RiskAmountUSD / (slPts * g_vpp);
   double lots    = MathRound(lotsRaw / volStp) * volStp;
   lots = MathMax(volMin, MathMin(volMax, lots));
   lots = NormalizeDouble(lots, 2);

   if(EnableDiagLog)
      Print("Lotaje: Risk=$", RiskAmountUSD, " / (SL=", DoubleToString(slPts,1),
            "pts × VPP=$", DoubleToString(g_vpp,6), ") = ", DoubleToString(lotsRaw,4),
            " → ", lots, " lotes");

   // --- Abrir orden ---
   MqlTradeRequest req = {};
   MqlTradeResult  res = {};

   double slPrice = 0, tpPrice = 0;

   if(g_breakoutDir == 1) // BUY
   {
      req.type  = ORDER_TYPE_BUY;
      req.price = ask;
      slPrice   = NormalizeDouble(ask - slDist, (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS));
      tpPrice   = NormalizeDouble(ask + slDist * TP3_RR, (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS));
   }
   else // SELL
   {
      req.type  = ORDER_TYPE_SELL;
      req.price = bid;
      slPrice   = NormalizeDouble(bid + slDist, (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS));
      tpPrice   = NormalizeDouble(bid - slDist * TP3_RR, (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS));
   }

   req.action    = TRADE_ACTION_DEAL;
   req.symbol    = Symbol();
   req.volume    = lots;
   req.sl        = slPrice;
   req.tp        = tpPrice;
   req.magic     = MagicNumber;
   req.comment   = StringFormat("BNY_SP500_%s_%s", (g_breakoutDir==1?"BUY":"SEL"), DayName(dow));
   req.type_filling = ORDER_FILLING_IOC;

   if(!OrderSend(req, res))
   {
      Print("❌ OrderSend FALLÓ: ", res.retcode, " — ", res.comment);
      g_tradeDoneToday = true;
      return;
   }

   g_ticket       = res.deal;
   g_entryPrice   = res.price;
   g_lotSize      = lots;
   g_tradeOpenToday = true;
   g_tradeDoneToday = true;
   g_breakoutPending = false;

   // Registrar en CSV
   LogTradeOpen(g_breakoutDir, res.price, slPrice, tpPrice, lots, slPts, utcHour, utcMin, dow);

   Print("✅ Trade abierto: ", (g_breakoutDir==1?"BUY":"SELL"),
         " | Entry=", DoubleToString(res.price,2),
         " | SL=", DoubleToString(slPrice,2),
         " | TP3=", DoubleToString(tpPrice,2),
         " | Lots=", lots,
         " | SL_pts=", DoubleToString(slPts,1));
}

//+------------------------------------------------------------------+
//| Gestión del trade abierto (BE / TP escalado / cierre forzoso)    |
//+------------------------------------------------------------------+
void ManageTrade(int utcHour, int utcMin, datetime serverNow)
{
   if(g_ticket == 0) return;

   // Buscar la posición abierta
   bool found = false;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(PositionGetTicket(i) == g_ticket ||
         (PositionGetInteger(POSITION_MAGIC) == MagicNumber &&
          PositionGetString(POSITION_SYMBOL) == Symbol()))
      {
         found = true;
         g_ticket = PositionGetTicket(i);
         break;
      }
   }

   if(!found)
   {
      // Posición ya cerrada (SL/TP/cierre manual)
      if(EnableDiagLog) Print("ℹ Posición ya cerrada (ticket=", g_ticket, ")");
      g_tradeOpenToday = false;
      g_ticket = 0;
      return;
   }

   // --- Cierre forzoso a SessionCloseHour UTC ---
   if(utcHour >= SessionCloseHour && utcMin >= SessionCloseMin)
   {
      ClosePosition("CIERRE_FORZOSO_17UTC");
      return;
   }

   double pt     = SymbolInfoDouble(Symbol(), SYMBOL_POINT);
   double slDist = g_slDistance * pt;
   double bid    = SymbolInfoDouble(Symbol(), SYMBOL_BID);
   double ask    = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   int    dig    = (int)SymbolInfoInteger(Symbol(), SYMBOL_DIGITS);

   // Calcular niveles
   double beLevel  = 0, tp1Level = 0, tp2Level = 0;
   double currentPrice = (g_breakoutDir == 1) ? bid : ask;

   if(g_breakoutDir == 1) // BUY
   {
      beLevel  = g_entryPrice + slDist * (BE_BufferPct / 100.0);
      tp1Level = g_entryPrice + slDist * TP1_RR;
      tp2Level = g_entryPrice + slDist * TP2_RR;
   }
   else // SELL
   {
      beLevel  = g_entryPrice - slDist * (BE_BufferPct / 100.0);
      tp1Level = g_entryPrice - slDist * TP1_RR;
      tp2Level = g_entryPrice - slDist * TP2_RR;
   }

   // --- BE: mover SL a entry ---
   if(!g_beActivated)
   {
      bool beTrigger = (g_breakoutDir == 1) ? (bid >= beLevel) : (ask <= beLevel);
      if(beTrigger)
      {
         double newSL = NormalizeDouble(g_entryPrice, dig);
         if(ModifySL(newSL))
         {
            g_beActivated = true;
            if(EnableDiagLog) Print("✓ BE activado: SL → entry=", DoubleToString(g_entryPrice,2));
         }
      }
   }

   // --- TP2: mover SL a TP1 ---
   if(g_beActivated && !g_tp2Activated)
   {
      bool tp2Trigger = (g_breakoutDir == 1) ? (bid >= tp2Level) : (ask <= tp2Level);
      if(tp2Trigger)
      {
         double newSL = NormalizeDouble(tp1Level, dig);
         if(ModifySL(newSL))
         {
            g_tp2Activated = true;
            if(EnableDiagLog) Print("✓ TP2 alcanzado: SL → TP1=", DoubleToString(tp1Level,2));
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Modificar SL de la posición abierta                              |
//+------------------------------------------------------------------+
bool ModifySL(double newSL)
{
   MqlTradeRequest req = {};
   MqlTradeResult  res = {};
   req.action   = TRADE_ACTION_SLTP;
   req.symbol   = Symbol();
   req.position = g_ticket;
   req.sl       = newSL;
   req.tp       = PositionGetDouble(POSITION_TP); // Mantener TP3

   if(!OrderSend(req, res))
   {
      Print("⚠ ModifySL falló: ", res.retcode, " — ", res.comment);
      return false;
   }
   return true;
}

//+------------------------------------------------------------------+
//| Cerrar posición abierta                                          |
//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   MqlTradeRequest req = {};
   MqlTradeResult  res = {};
   req.action    = TRADE_ACTION_DEAL;
   req.symbol    = Symbol();
   req.position  = g_ticket;
   req.volume    = PositionGetDouble(POSITION_VOLUME);
   req.magic     = MagicNumber;
   req.comment   = reason;

   if(PositionGetInteger(POSITION_TYPE) == POSITION_TYPE_BUY)
   {
      req.type  = ORDER_TYPE_SELL;
      req.price = SymbolInfoDouble(Symbol(), SYMBOL_BID);
   }
   else
   {
      req.type  = ORDER_TYPE_BUY;
      req.price = SymbolInfoDouble(Symbol(), SYMBOL_ASK);
   }
   req.type_filling = ORDER_FILLING_IOC;

   if(!OrderSend(req, res))
      Print("⚠ ClosePosition falló: ", res.retcode, " (", reason, ")");
   else
   {
      Print("✓ Posición cerrada: ", reason, " @ ", DoubleToString(res.price,2));
      g_tradeOpenToday = false;
      g_ticket = 0;
   }
}

//+------------------------------------------------------------------+
//| CSV Logger — Inicialización                                      |
//+------------------------------------------------------------------+
void InitCSVLog()
{
   g_csvFileName = StringFormat("BreakoutNY_SP500_%s.csv",
                                TimeToString(TimeCurrent(), TIME_DATE));
   StringReplace(g_csvFileName, ".", "-");
   StringReplace(g_csvFileName, " ", "_");

   g_csvHandle = FileOpen(g_csvFileName, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(g_csvHandle == INVALID_HANDLE)
   {
      Print("⚠ No se pudo crear CSV log: ", g_csvFileName);
      return;
   }

   // Header
   FileWrite(g_csvHandle,
             "Date", "UTC_Time", "DOW", "Direction",
             "Entry", "SL", "TP3", "Lots", "SL_Pts",
             "VPP", "Risk_USD", "Symbol");
   Print("✓ CSV log iniciado: ", g_csvFileName);
}

//+------------------------------------------------------------------+
//| CSV Logger — Registrar apertura de trade                         |
//+------------------------------------------------------------------+
void LogTradeOpen(int dir, double entry, double sl, double tp,
                  double lots, double slPts, int utcH, int utcM, int dow)
{
   if(g_csvHandle == INVALID_HANDLE) return;

   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   string dateStr = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
   string timeStr = StringFormat("%02d:%02d UTC", utcH, utcM);

   FileWrite(g_csvHandle,
             dateStr, timeStr, DayName(dow),
             (dir==1?"BUY":"SELL"),
             DoubleToString(entry,2),
             DoubleToString(sl,2),
             DoubleToString(tp,2),
             DoubleToString(lots,2),
             DoubleToString(slPts,1),
             DoubleToString(g_vpp,6),
             DoubleToString(RiskAmountUSD,2),
             Symbol());
   FileFlush(g_csvHandle);
}

//+------------------------------------------------------------------+
//| Utilidad: nombre del día                                         |
//+------------------------------------------------------------------+
string DayName(int dow)
{
   switch(dow)
   {
      case 0: return "Dom";
      case 1: return "Lun";
      case 2: return "Mar";
      case 3: return "Mie";
      case 4: return "Jue";
      case 5: return "Vie";
      case 6: return "Sab";
   }
   return "???";
}

