string VisMakeDayTag()
{
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   return StringFormat("%04d%02d%02d", dt.year, dt.mon, dt.day);
}

void VisRedrawAll()
{
   if(!VIS_Enable) return;
   datetime cutoff = TimeCurrent() - (datetime)VIS_LookbackDays * 86400;
   for(int i = ObjectsTotal(0,-1,-1)-1; i >= 0; i--)
   {
      string name = ObjectName(0,i);
      if(StringFind(name, VIS_PFX) == 0 &&
         ObjectGetInteger(0, name, OBJPROP_TIME) < cutoff)
         ObjectDelete(0, name);
   }
   ChartRedraw(0);
}

void VisRedrawToday()
{
   if(!VIS_Enable || g_vis_dayTag == "") return;
   int dig = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);

   // Zona rango
   if(g_rangeCalculated)
   {
      datetime t35 = 0, t45e = 0;
      MqlRates rates[]; ArraySetAsSeries(rates, true);
      if(CopyRates(_Symbol, PERIOD_M5, 0, 60, rates) > 0)
         for(int i = 0; i < ArraySize(rates); i++)
         {
            MqlDateTime rd;
            TimeToStruct(rates[i].time - (long)ServerOffsetHours*3600, rd);
            if(rd.hour==14 && rd.min==35) t35  = rates[i].time;
            if(rd.hour==14 && rd.min==45) t45e = rates[i].time + 300;
         }
      if(t35 > 0 && t45e > 0)
      {
         string rn = VIS_PFX+"RNG_"+g_vis_dayTag;
         if(ObjectFind(0,rn)<0) ObjectCreate(0,rn,OBJ_RECTANGLE,0,t35,g_rangeHigh,t45e,g_rangeLow);
         ObjectSetInteger(0,rn,OBJPROP_COLOR, VIS_ColRangeBorder);
         ObjectSetInteger(0,rn,OBJPROP_FILL,  true);
         ObjectSetInteger(0,rn,OBJPROP_BACK,  true);
      }
   }

   // Niveles del trade
   if(g_entryPrice > 0)
   {
      datetime t0  = iTime(_Symbol, PERIOD_M5, 0);
      datetime t1  = t0 + (datetime)VIS_ExtendBars * 300;
      double slDist = g_slDistance;
      double sl, tp1, tp2, tp3, be;
      if(g_breakoutDir == 1)
      {
         sl  = g_entryPrice - slDist;
         tp1 = g_entryPrice + slDist * TP1_RR;
         tp2 = g_entryPrice + slDist * TP2_RR;
         tp3 = g_entryPrice + slDist * TP3_RR;
         be  = g_entryPrice + slDist * (BE_BufferPct/100.0);
      }
      else
      {
         sl  = g_entryPrice + slDist;
         tp1 = g_entryPrice - slDist * TP1_RR;
         tp2 = g_entryPrice - slDist * TP2_RR;
         tp3 = g_entryPrice - slDist * TP3_RR;
         be  = g_entryPrice - slDist * (BE_BufferPct/100.0);
      }
      VisLine(VIS_PFX+"ENTRY_"+g_vis_dayTag, t0, t1, g_entryPrice, VIS_ColEntry, "Entry", 2);
      VisLine(VIS_PFX+"SL_"   +g_vis_dayTag, t0, t1, sl,           VIS_ColSL,    "SL",    1);
      VisLine(VIS_PFX+"TP1_"  +g_vis_dayTag, t0, t1, tp1,          VIS_ColTP1,   "TP1",   1);
      VisLine(VIS_PFX+"TP2_"  +g_vis_dayTag, t0, t1, tp2,          VIS_ColTP2,   "TP2",   2);
      VisLine(VIS_PFX+"TP3_"  +g_vis_dayTag, t0, t1, tp3,          VIS_ColTP3,   "TP3",   3);
      if(VIS_ShowBE)
         VisLine(VIS_PFX+"BE_"+g_vis_dayTag, t0, t1, be, VIS_ColBE, "BE", 1);
      if(VIS_ShowLabel)
      {
         string lbName = VIS_PFX+"LBL_"+g_vis_dayTag;
         string dirUp = (g_breakoutDir==1) ? "BUY" : "SELL";
         string txt = StringFormat("%s | SL=%dpts | BE=%.0f%% | TP3=%dpts",
                                   dirUp, g_slPoints,
                                   BE_BufferPct,
                                   (int)MathRound(g_slPoints * TP3_RR));
         if(ObjectFind(0,lbName)<0)
            ObjectCreate(0,lbName,OBJ_TEXT,0,t0,tp3+(g_breakoutDir==1?slDist:-slDist)*0.2);
         ObjectSetString (0,lbName,OBJPROP_TEXT,     txt);
         ObjectSetInteger(0,lbName,OBJPROP_COLOR,    VIS_ColTP3);
         ObjectSetInteger(0,lbName,OBJPROP_FONTSIZE,  8);
      }
      // Flecha
      string arrName = VIS_PFX+"ARR_"+g_vis_dayTag;
      if(ObjectFind(0,arrName)<0)
      {
         ObjectCreate(0,arrName,OBJ_ARROW,0,TimeCurrent(),g_entryPrice);
         ObjectSetInteger(0,arrName,OBJPROP_ARROWCODE, g_breakoutDir==1?233:234);
         ObjectSetInteger(0,arrName,OBJPROP_COLOR,     g_breakoutDir==1?clrLime:clrRed);
         ObjectSetInteger(0,arrName,OBJPROP_WIDTH,2);
      }
   }
   ChartRedraw(0);
}

void VisLine(string name, datetime t1, datetime t2, double price,
             color col, string label, int width)
{
   if(ObjectFind(0,name)<0) ObjectCreate(0,name,OBJ_TREND,0,t1,price,t2,price);
   ObjectMove(0,name,0,t1,price); ObjectMove(0,name,1,t2,price);
   ObjectSetInteger(0,name,OBJPROP_COLOR,     col);
   ObjectSetInteger(0,name,OBJPROP_WIDTH,     width);
   ObjectSetInteger(0,name,OBJPROP_RAY_RIGHT, false);
   ObjectSetString (0,name,OBJPROP_TEXT,      label+" "+DoubleToString(price,_Digits));
}
