input color  VIS_ColRangeBorder = C'55,115,215';
input color  VIS_ColSL          = C'220,50,70';
input color  VIS_ColEntry       = C'195,208,230';
input color  VIS_ColBE          = C'0,195,218';
input color  VIS_ColTP1         = C'228,188,38';
