input group "=== IDENTIFICACIÓN ==="
input ulong  MagicNumber        = 202404; // XAUUSD exclusivo

//===================================================================
//  VARIABLES GLOBALES
//===================================================================

CTrade        trade;
CPositionInfo posInfo;

// VPP — calculado una vez en OnInit, verificado con OrderCalcProfit
double g_vpp            = 0.0;

// ATR handle
int    g_atrHandle      = INVALID_HANDLE;

// Estado del rango (puntos enteros — igual que SP500)
double g_rangeHigh      = 0.0;
double g_rangeLow       = 0.0;
double g_slDistance     = 0.0;  // en precio (para cálculos de SL/TP)
int    g_slPoints       = 0;    // en puntos enteros (para filtros MinSL/MaxSL)
bool   g_rangeCalculated = false;

// Estado breakout (arquitectura SP500 con int para dirección)
bool     g_breakoutPending = false;
int      g_breakoutDir     = 0;  // +1 BUY, -1 SELL
datetime g_breakoutBarTime = 0;

// Estado trade
bool   g_tradeOpenToday  = false;
bool   g_tradeDoneToday  = false;
ulong  g_ticket          = 0;
bool   g_beActivated     = false;
bool   g_tp2Activated    = false;
double g_entryPrice      = 0.0;
double g_lotSize         = 0.0;

// Día actual
datetime g_lastBarTime   = 0;
datetime g_lastResetDay  = 0;
int      g_todayDOW      = 0;

// Filtro de tendencia
double g_tf_prevClose    = 0.0;
string g_tf_allowedDir   = "both";

// Estadísticas OnTester
int    stat_total        = 0;
int    stat_wins         = 0;
int    stat_losses       = 0;
double stat_grossProfit  = 0.0;
double stat_grossLoss    = 0.0;

// CSV
int    g_csvHandle       = INVALID_HANDLE;

// Visual
#define VIS_PFX "BNY2XAU_"
string g_vis_dayTag      = "";

//===================================================================
//  OnInit
//===================================================================

int OnInit()
{
   // Validaciones
   if(TP1_RR <= 0 || TP2_RR <= TP1_RR || TP3_RR <= TP2_RR)
   { Alert("ERROR: TP1 < TP2 < TP3 deben ser crecientes."); return INIT_PARAMETERS_INCORRECT; }
   if(BE_BufferPct < 30 || BE_BufferPct > 400)
   { Alert("ERROR: BE_BufferPct debe ser 30-400."); return INIT_PARAMETERS_INCORRECT; }
   if(TP1_ClosePct + TP2_ClosePct >= 100)
   { Alert("ERROR: TP1+TP2 ClosePct debe ser < 100."); return INIT_PARAMETERS_INCORRECT; }
   if(MinSL_Points >= MaxSL_Points)
   { Alert("ERROR: MinSL_Points debe ser < MaxSL_Points."); return INIT_PARAMETERS_INCORRECT; }

   trade.SetExpertMagicNumber(MagicNumber);

   // 1. VPP — Formula B base, verificar con OrderCalcProfit
   DiagnoseAndSetVPP();
   if(g_vpp <= 0.0) { Print("ERROR CRITICO: VPP=0. Verificar simbolo."); return INIT_FAILED; }

   // 2. ATR handle
   g_atrHandle = iATR(_Symbol, PERIOD_M5, ATR_Period);
   if(g_atrHandle == INVALID_HANDLE)
   { Print("ERROR: No se pudo crear handle ATR."); return INIT_FAILED; }

   // 3. CSV
   if(EnableCSV) InitCSV();

   // 4. Resumen
   Print("=== BreakoutNY v2.0 XAUUSD — FundingPips ===");
   Print("VPP confirmado : $", DoubleToString(g_vpp, 4), "/pt/lot");
   Print("Sesion close   : ", SessionCloseHour, ":00 UTC");
   Print("Rango          : [", MinSL_Points, " – ", MaxSL_Points, "] pts");
   Print("BE             : ", BE_BufferPct, "% | TP3=", TP3_RR, "R");
   Print("Direccion      : BUY=", EnableBuy?"ON":"OFF", " SELL=", EnableSell?"ON":"OFF");
   Print("TF_Enable      : ", TF_Enable?"SI":"NO");
   Print("Dias           : L=", FilterMonday?"S":"N",
         " M=", FilterTuesday?"S":"N",
         " X=", FilterWednesday?"S":"N",
         " J=", FilterThursday?"S":"N",
         " V=", FilterFriday?"S":"N");

   // Tabla de lotaje
   Print("--- Tabla de lotaje (Risk=$", RiskAmountUSD, ") ---");
   int slTests[] = {250, 400, 600, 800, 1000, 1400, 1700};
   double ls = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double mn = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double mx = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 5.0);
   for(int i = 0; i < ArraySize(slTests); i++)
   {
      double slPts = slTests[i];
      double lRaw  = RiskAmountUSD / (slPts * g_vpp);
      double lNorm = MathMax(mn, MathMin(mx, MathFloor(lRaw/ls)*ls));
      double rReal = slPts * g_vpp * lNorm;
      Print("  SL=", slTests[i], "pts → ", DoubleToString(lNorm,2), " lots | Risk=$", DoubleToString(rReal,2));
   }
   Print("=========================================");

   VisRedrawAll();
   return INIT_SUCCEEDED;
}

//===================================================================
//  VPP — Diagnóstico y configuración (arquitectura SP500 mejorada)
//===================================================================

void DiagnoseAndSetVPP()
{
   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double tv  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double ts  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   Print("--- [VPP XAUUSD] ContractSize=", cs, " TickSize=", ts,
         " TickValue=", tv, " Point=", pt);

   // Formula B (siempre disponible) — base
   double vppB = cs * pt;

   // Formula A (si TV y TS disponibles)
   double vppA = (tv > 0 && ts > 0) ? tv / ts : 0.0;
   if(vppA > 0)
      Print("VPP-A (tv/ts)  = $", DoubleToString(vppA,6));
   else
      Print("VPP-A (tv/ts)  = N/A (TS=0 o TV=0)");
   Print("VPP-B (cs*pt)  = $", DoubleToString(vppB,6), " <- base");

   // OrderCalcProfit — VERDAD ABSOLUTA
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double profitTest = 0.0;
   bool ok = OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0,
                             ask, ask + 100.0 * pt, profitTest);
   if(ok && profitTest > 0)
   {
      double vppOCP = profitTest / 100.0;
      Print("VPP-C (OCP)    = $", DoubleToString(vppOCP,6),
            " <- VERDAD ABSOLUTA (100pts x 1lot = $", DoubleToString(profitTest,2), ")");

      // Verificar consistencia
      if(MathAbs(vppOCP - 1.0) < 0.01)
         Print("✓ VPP = $1.00/pt/lot CONFIRMADO");
      else
         Print("⚠ VPP inesperado = $", DoubleToString(vppOCP,4), " — revisar");

      g_vpp = vppOCP; // Usar OCP como verdad
   }
   else
   {
      Print("⚠ OrderCalcProfit no disponible — usando VPP-B");
      g_vpp = (vppA > 0) ? vppA : vppB; // Preferir A si disponible
      if(MathAbs(g_vpp - 1.0) < 0.01)
         Print("✓ VPP estimado = $1.00/pt/lot (fórmula)");
   }

   Print("VPP activo     = $", DoubleToString(g_vpp,4), "/pt/lot");
}

//===================================================================
//  OnDeinit
//===================================================================

void OnDeinit(const int reason)
{
   if(g_atrHandle != INVALID_HANDLE) IndicatorRelease(g_atrHandle);
   if(g_csvHandle != INVALID_HANDLE) { FileFlush(g_csvHandle); FileClose(g_csvHandle); }
   // Limpiar visual
   for(int i = ObjectsTotal(0,-1,-1)-1; i >= 0; i--)
      if(StringFind(ObjectName(0,i), VIS_PFX) == 0)
         ObjectDelete(0, ObjectName(0,i));
   ChartRedraw(0);
}

//===================================================================
//  OnTester
//===================================================================

double OnTester()
{
   if(stat_total == 0) return 0;
   double pf = (stat_grossLoss != 0) ? stat_grossProfit / MathAbs(stat_grossLoss) : 0;
   double wr = (double)stat_wins / stat_total * 100.0;
   Print("=== XAUUSD v2.0 RESUMEN ===");
   Print("Trades:", stat_total, " W=", stat_wins, " L=", stat_losses,
         " WR=", DoubleToString(wr,1), "% PF=", DoubleToString(pf,3));
   return pf;
}

//===================================================================
//  OnTradeTransaction — captura cierres para CSV y estadísticas
//===================================================================

void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &req,
                        const MqlTradeResult  &res)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
   if(!HistoryDealSelect(trans.deal)) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_MAGIC) != (long)MagicNumber) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;

   double exitPrice = HistoryDealGetDouble(trans.deal, DEAL_PRICE);
   double profit    = HistoryDealGetDouble(trans.deal, DEAL_PROFIT);
   double swap      = HistoryDealGetDouble(trans.deal, DEAL_SWAP);
   double comm      = HistoryDealGetDouble(trans.deal, DEAL_COMMISSION);
   double total     = profit + swap + comm;

   stat_total++;
   if(total >= 0) { stat_wins++;   stat_grossProfit += total; }
   else            { stat_losses++; stat_grossLoss   += total; }

   if(EnableCSV && g_csvHandle != INVALID_HANDLE)
      WriteTradeClose(exitPrice, total, profit, swap, comm);
}

//===================================================================
//  OnTick — lógica principal
//===================================================================

void OnTick()
{
   datetime barTime = iTime(_Symbol, PERIOD_M5, 0);
   bool     isNewBar = (barTime != g_lastBarTime);
   if(isNewBar) g_lastBarTime = barTime;

   // UTC actual
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int utcH = (dt.hour - ServerOffsetHours + 24) % 24;
   int utcM = dt.min;
   int dow  = dt.day_of_week;

   // Reset diario explícito a las 14:30 UTC (arquitectura SP500)
   // Esto garantiza estado limpio antes de la ventana, independiente del día
   if(isNewBar && utcH == 14 && utcM == 30)
   {
      ResetDaily(dow);
      g_vis_dayTag = VisMakeDayTag();
      VisRedrawAll();
   }

   // Reset adicional por cambio de fecha (seguridad para servidores con offset extraño)
   MqlDateTime sdt; TimeToStruct(TimeCurrent(), sdt);
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00", sdt.year, sdt.mon, sdt.day));
   if(today != g_lastResetDay && utcH >= 0 && utcH < 12)
   {
      g_lastResetDay = today;
      if(!g_tradeOpenToday) ResetDaily(dow);
   }

   // --- Si hay trade abierto: gestionar ---
   if(g_tradeOpenToday && g_ticket > 0)
   {
      ManageTrade(utcH, utcM);
      return;
   }

   // --- Ya operamos hoy: nada más ---
   if(g_tradeDoneToday) return;

   // --- Calcular rango en 14:50 UTC (nueva barra) ---
   if(isNewBar && utcH == 14 && utcM == 50 && !g_rangeCalculated)
   {
      CalculateRange();
      return;
   }

   if(!g_rangeCalculated) return;

   // --- Ventana de entrada ---
   bool inWindow = (utcH == 14 && utcM >= 50) ||
                   (utcH == 15 && utcM < EntryWindowEnd_Min);

   if(!inWindow)
   {
      // Ventana cerrada sin entrada
      if(g_breakoutPending)
      {
         if(EnableDiagLog) Print("Ventana cerrada con breakout pendiente — cancelado");
         g_breakoutPending = false;
      }
      if(!g_tradeOpenToday && !g_tradeDoneToday)
         g_tradeDoneToday = true;
      return;
   }

   // --- Fase A: detectar breakout (en cada tick) ---
   if(!g_breakoutPending && !g_tradeOpenToday)
      DetectBreakout();

   // --- Fase B: confirmar y entrar (solo en nueva barra) ---
   if(g_breakoutPending && isNewBar && !g_tradeOpenToday)
      ConfirmAndEnter(utcH, utcM, dow);
}

//===================================================================
//  ResetDaily
//===================================================================

void ResetDaily(int dow)
{
   g_rangeCalculated  = false;
   g_rangeHigh        = 0.0;
   g_rangeLow         = 0.0;
   g_slDistance       = 0.0;
   g_slPoints         = 0;
   g_breakoutPending  = false;
   g_breakoutDir      = 0;
   g_breakoutBarTime  = 0;
   g_tradeOpenToday   = false;
   g_tradeDoneToday   = false;
   g_ticket           = 0;
   g_beActivated      = false;
   g_tp2Activated     = false;
   g_entryPrice       = 0.0;
   g_lotSize          = 0.0;
   g_todayDOW         = dow;

   // PrevClose para filtro TF: última vela ≤17:00 UTC del día anterior
   if(TF_Enable)
   {
      g_tf_prevClose   = 0.0;
      g_tf_allowedDir  = "both";
      MqlRates rates[];
      ArraySetAsSeries(rates, true);
      int copied = CopyRates(_Symbol, PERIOD_M5, 0, 600, rates);
      if(copied > 0)
      {
         MqlDateTime nowDt;
         TimeToStruct(TimeCurrent() - (long)ServerOffsetHours * 3600, nowDt);
         int todayDay = nowDt.day; int todayMon = nowDt.mon; int todayYear = nowDt.year;

         for(int i = 0; i < copied; i++)
         {
            MqlDateTime rd;
            TimeToStruct(rates[i].time - (long)ServerOffsetHours * 3600, rd);
            bool isYesterday = (rd.year < todayYear) ||
                               (rd.year == todayYear && rd.mon < todayMon) ||
                               (rd.year == todayYear && rd.mon == todayMon && rd.day < todayDay);
            if(isYesterday && (rd.hour < 17 || (rd.hour == 16 && rd.min <= 55)))
            {
               g_tf_prevClose = rates[i].close;
               if(EnableDiagLog)
                  Print("TF prevClose=", DoubleToString(g_tf_prevClose, _Digits),
                        " @ ", TimeToString(rates[i].time, TIME_DATE|TIME_MINUTES), " UTC");
               break;
            }
         }
         if(g_tf_prevClose <= 0 && EnableDiagLog)
            Print("TF: prevClose no encontrado — TF inactivo hoy");
      }
   }
   else g_tf_allowedDir = "both";

   if(EnableDiagLog)
      Print("✦ Reset diario | ", DayName(dow), " | TF_prevClose=",
            DoubleToString(g_tf_prevClose, _Digits));
}

//===================================================================
//  CalculateRange — arquitectura SP500 (iHigh/iLow por índice)
//===================================================================

void CalculateRange()
{
   // Velas cerradas: índice 3=14:35, 2=14:40, 1=14:45
   // Vela 0 = 14:50, aún abierta
   double h3 = iHigh(_Symbol, PERIOD_M5, 3);
   double h2 = iHigh(_Symbol, PERIOD_M5, 2);
   double h1 = iHigh(_Symbol, PERIOD_M5, 1);
   double l3 = iLow (_Symbol, PERIOD_M5, 3);
   double l2 = iLow (_Symbol, PERIOD_M5, 2);
   double l1 = iLow (_Symbol, PERIOD_M5, 1);

   if(h3 <= 0 || l3 <= 0)
   { Print("ERROR: No hay datos de velas para el rango."); return; }

   g_rangeHigh  = MathMax(h3, MathMax(h2, h1));
   g_rangeLow   = MathMin(l3, MathMin(l2, l1));
   g_slDistance = g_rangeHigh - g_rangeLow;                          // en precio
   g_slPoints   = (int)MathRound(g_slDistance / _Point);             // en puntos enteros

   // Filtro MinSL / MaxSL
   if(g_slPoints < MinSL_Points)
   {
      if(EnableDiagLog) Print("⊘ Rango PEQUEÑO: ", g_slPoints, " pts < MinSL=", MinSL_Points);
      g_tradeDoneToday = true; WriteFilteredRow("range_small"); return;
   }
   if(g_slPoints > MaxSL_Points)
   {
      if(EnableDiagLog) Print("⊘ Rango GRANDE: ", g_slPoints, " pts > MaxSL=", MaxSL_Points);
      g_tradeDoneToday = true; WriteFilteredRow("range_large"); return;
   }

   // Filtro ATR
   if(ATR_FilterEnable && !CheckATRFilter())
   { g_tradeDoneToday = true; return; }

   // Filtro día
   if(!CheckDayFilter())
   { g_tradeDoneToday = true; return; }

   // Filtro tendencia TF
   if(TF_Enable && g_tf_prevClose > 0)
   {
      double midRange = (g_rangeHigh + g_rangeLow) / 2.0;
      double thresh   = TF_Threshold_Pts * _Point;

      if(midRange > g_tf_prevClose + thresh)       g_tf_allowedDir = "buy";
      else if(midRange < g_tf_prevClose - thresh)  g_tf_allowedDir = "sell";
      else g_tf_allowedDir = TF_BlockNeutral ? "none" : "both";

      if(EnableDiagLog)
         Print("TF | mid=", DoubleToString(midRange,_Digits),
               " prevClose=", DoubleToString(g_tf_prevClose,_Digits),
               " → dir=", g_tf_allowedDir);

      if(g_tf_allowedDir == "none")
      {
         if(EnableDiagLog) Print("⊘ TF: zona neutra — sin operación");
         g_tradeDoneToday = true; WriteFilteredRow("tf_neutral"); return;
      }
   }

   g_rangeCalculated = true;
   if(EnableDiagLog)
      Print("✓ Rango OK: H=", DoubleToString(g_rangeHigh,_Digits),
            " L=", DoubleToString(g_rangeLow,_Digits),
            " SL=", g_slPoints, "pts | TF=", g_tf_allowedDir,
            " | ", DayName(g_todayDOW));
   VisRedrawToday();
}

//===================================================================
//  Filtro ATR (arquitectura SP500 — más simple)
//===================================================================

bool CheckATRFilter()
{
   double buf[];
   ArraySetAsSeries(buf, true);
   int copied = CopyBuffer(g_atrHandle, 0, 1, ATR_BaselineDays + 2, buf);
   if(copied < ATR_BaselineDays + 1) { Print("ATR: datos insuficientes"); return true; }

   double curATR = buf[0];
   double sum = 0;
   for(int i = 1; i <= ATR_BaselineDays; i++) sum += buf[i];
   double baseATR = sum / ATR_BaselineDays;
   if(baseATR <= 0) return true;

   double ratio = curATR / baseATR;

   if(ratio > ATR_MaxMultiplier)
   {
      if(EnableDiagLog) Print("⊘ ATR ALTO: ", DoubleToString(ratio,2), "× > ", ATR_MaxMultiplier, "×");
      WriteFilteredRow("atr_high"); return false;
   }
   if(ratio < ATR_MinMultiplier)
   {
      if(EnableDiagLog) Print("⊘ ATR BAJO: ", DoubleToString(ratio,2), "× < ", ATR_MinMultiplier, "×");
      WriteFilteredRow("atr_low"); return false;
   }
   if(EnableDiagLog)
      Print("✓ ATR OK: ", DoubleToString(ratio,2), "× | base=", DoubleToString(baseATR,1), "pts");
   return true;
}

