string DayName(int dow)
{
   string n[] = {"Dom","Lun","Mar","Mie","Jue","Vie","Sab"};
   return (dow >= 0 && dow <= 6) ? n[dow] : "???";
}

//===================================================================
//  CSV
//===================================================================

void InitCSV()
{
   string fname = "BreakoutNY_v2_XAUUSD_trades.csv";
   g_csvHandle = FileOpen(fname, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(g_csvHandle == INVALID_HANDLE) { Print("⚠ No se pudo crear CSV"); return; }
   FileWrite(g_csvHandle,
      "Date","DOW","Direction","Entry","SL","TP3","Lots","SL_pts",
      "VPP","Risk_USD","BE_Pct","TF_dir","FilteredBy","ExitPrice","Profit","Swap","Comm","Net");
   Print("✓ CSV iniciado: ", fname);
}

void WriteTradeOpen(double entry, double sl, double tp, double lots, int dow)
{
   if(g_csvHandle == INVALID_HANDLE) return;
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   string dateStr = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
   FileWrite(g_csvHandle,
      dateStr, DayName(dow), (g_breakoutDir==1?"BUY":"SELL"),
      DoubleToString(entry,_Digits), DoubleToString(sl,_Digits), DoubleToString(tp,_Digits),
      DoubleToString(lots,2), g_slPoints,
      DoubleToString(g_vpp,4), DoubleToString(RiskAmountUSD,2),
      DoubleToString(BE_BufferPct,0), g_tf_allowedDir, "");
   FileFlush(g_csvHandle);
}

void WriteTradeClose(double exitPrice, double net, double profit, double swap, double comm)
{
   // Nota: esta función se llama desde OnTradeTransaction
   // El CSV ya tiene la fila de apertura — aquí agregamos una fila de cierre separada
   if(g_csvHandle == INVALID_HANDLE) return;
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   string dateStr = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
   FileWrite(g_csvHandle,
      dateStr, "", "CLOSE", "", "", "", "", "", "", "", "", "", "",
      DoubleToString(exitPrice,_Digits),
      DoubleToString(profit,2), DoubleToString(swap,2), DoubleToString(comm,2),
      DoubleToString(net,2));
   FileFlush(g_csvHandle);
}

void WriteFilteredRow(string reason)
{
   if(!EnableCSV || g_csvHandle == INVALID_HANDLE) return;
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   string dateStr = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
   FileWrite(g_csvHandle,
      dateStr, DayName(g_todayDOW), "FILTERED", "", "", "", "", g_slPoints,
      "", "", "", g_tf_allowedDir, reason, "", "", "", "", "");
   FileFlush(g_csvHandle);
}

